"""COGNISEC — Flask Application"""
import time, json, threading
from flask import Flask, jsonify, Response, request, make_response
from engine import orchestrator

app = Flask(__name__)
_started = False
_slock = threading.Lock()

def ensure_started():
    global _started
    if not _started:
        with _slock:
            if not _started:
                orchestrator.start()
                _started = True

@app.before_request
def _boot(): ensure_started()

HTML_PAGES = {'overview': '<!DOCTYPE html>\n<html lang="en">\n<head>\n<title>COGNISEC — Overview</title>\n\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<link href="https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Rajdhani:wght@400;600;700&family=Exo+2:wght@300;700;900&display=swap" rel="stylesheet">\n<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>\n<style>\n:root{\n  --bg:#0d1117;--bg2:#111b24;--panel:#152030;--panel2:#182535;\n  --border:#2a4a64;--accent:#a8d8f0;--green:#7fefd4;--orange:#ff9f43;\n  --red:#ff6b8a;--purple:#b8d4f0;--muted:#4a7a9b;--text:#e0f0f8;\n  --mono:\'Share Tech Mono\',monospace;--sans:\'Rajdhani\',sans-serif;\n}\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\nhtml{font-size:16px;scroll-behavior:smooth}\nbody{background:var(--bg);color:var(--text);font-family:var(--sans);min-height:100vh;overflow-x:hidden;font-size:1rem}\nbody::before{content:\'\';position:fixed;inset:0;\n  background-image:linear-gradient(rgba(168,216,240,.022) 1px,transparent 1px),\n  linear-gradient(90deg,rgba(168,216,240,.022) 1px,transparent 1px);\n  background-size:44px 44px;pointer-events:none;z-index:0}\nbody::after{content:\'\';position:fixed;inset:0;\n  background:repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,.05) 3px,rgba(0,0,0,.05) 4px);\n  pointer-events:none;z-index:9998}\n\n/* ── SIDEBAR NAV ── */\n#sidebar{\n  position:fixed;left:0;top:0;bottom:0;width:200px;\n  background:rgba(13,17,23,.97);border-right:1px solid var(--border);\n  display:flex;flex-direction:column;z-index:1000;\n  backdrop-filter:blur(12px);\n}\n.sb-logo{padding:18px 16px 14px;border-bottom:1px solid var(--border)}\n.sb-logo-text{font-family:var(--mono);font-size:1.1rem;color:var(--accent);\n  letter-spacing:4px;text-shadow:0 0 14px rgba(168,216,240,.45)}\n.sb-logo-text span{color:var(--green)}\n.sb-logo-sub{font-family:var(--mono);font-size:.72rem;color:var(--muted);\n  letter-spacing:2px;margin-top:3px}\n.sb-status{display:flex;align-items:center;gap:6px;padding:10px 16px;\n  border-bottom:1px solid var(--border);font-family:var(--mono);font-size:.75rem;color:var(--green)}\n.sb-dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:pulse 1.5s infinite}\n@keyframes pulse{0%,100%{opacity:1;box-shadow:0 0 6px var(--green)}50%{opacity:.3;box-shadow:none}}\n.sb-nav{flex:1;padding:10px 0;overflow-y:auto}\n.sb-nav a{\n  display:flex;align-items:center;gap:10px;\n  padding:10px 16px;text-decoration:none;\n  font-family:var(--sans);font-size:.92rem;font-weight:600;\n  letter-spacing:1.5px;text-transform:uppercase;\n  color:var(--muted);border-left:2px solid transparent;\n  transition:all .2s;\n}\n.sb-nav a:hover{color:var(--text);background:rgba(168,216,240,.04);border-left-color:var(--muted)}\n.sb-nav a.active{color:var(--accent);background:rgba(168,216,240,.06);border-left-color:var(--accent)}\n.sb-nav a .nav-icon{font-size:1rem;width:18px;text-align:center}\n.sb-nav .nav-badge{margin-left:auto;font-family:var(--mono);font-size:.68rem;\n  padding:1px 5px;border:1px solid rgba(168,216,240,.2);color:var(--muted)}\n.sb-nav a.active .nav-badge{border-color:rgba(168,216,240,.4);color:var(--accent)}\n.sb-footer{padding:12px 16px;border-top:1px solid var(--border)}\n.sb-clock{font-family:var(--mono);font-size:.78rem;color:var(--muted)}\n.sb-cmd{font-family:var(--mono);font-size:.72rem;color:rgba(58,106,132,.5);\n  margin-top:6px;line-height:1.6}\n.sb-cmd span{color:var(--accent)}\n\n/* ── PAGE WRAPPER ── */\n#page{margin-left:200px;position:relative;z-index:1;padding:16px;min-height:100vh}\n\n/* ── PAGE HEADER ── */\n.page-hdr{margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;justify-content:space-between}\n.page-title{font-family:var(--mono);font-size:1.2rem;color:var(--accent);letter-spacing:3px;text-transform:uppercase}\n.page-sub{font-size:.85rem;color:var(--muted);margin-top:3px}\n.page-meta{font-family:var(--mono);font-size:.75rem;color:var(--muted)}\n\n/* ── STAT CARDS ── */\n.stat-row{display:grid;gap:10px;margin-bottom:16px}\n.stat-card{background:var(--panel);border:1px solid var(--border);padding:14px 18px;position:relative;overflow:hidden}\n.stat-card::before{content:\'\';position:absolute;top:0;left:0;width:100%;height:2px;\n  background:linear-gradient(90deg,var(--ca,var(--accent)),var(--cb,var(--green)))}\n.stat-label{font-family:var(--mono);font-size:.72rem;letter-spacing:2px;color:var(--muted);\n  text-transform:uppercase;margin-bottom:6px}\n.stat-val{font-family:var(--mono);font-size:2.2rem;color:#fff;line-height:1;transition:all .3s}\n.stat-val.bump{color:var(--accent);text-shadow:0 0 18px rgba(168,216,240,.5)}\n.stat-sub{font-size:.75rem;color:var(--muted);margin-top:3px}\n\n/* ── PANEL ── */\n.panel{background:var(--panel);border:1px solid var(--border);display:flex;flex-direction:column;overflow:hidden}\n.panel-hdr{padding:9px 13px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;gap:8px;flex-shrink:0}\n.panel-title{font-family:var(--mono);font-size:.78rem;letter-spacing:2px;text-transform:uppercase;color:var(--accent)}\n.panel-badge{margin-left:auto;font-family:var(--mono);font-size:.72rem;\n  padding:2px 8px;border:1px solid rgba(168,216,240,.22);color:var(--muted)}\n.panel-body{flex:1;overflow:hidden;padding:12px}\n.panel-scroll{overflow-y:auto}\n.panel-nopad{padding:0}\n\n/* ── RISK BADGES ── */\n.risk{font-size:.72rem;padding:1px 5px;border-radius:2px;text-transform:uppercase;font-weight:700;letter-spacing:1px}\n.risk-critical{background:rgba(255,107,138,.14);color:var(--red);border:1px solid rgba(255,107,138,.3)}\n.risk-high{background:rgba(255,159,67,.1);color:var(--orange);border:1px solid rgba(255,159,67,.3)}\n.risk-medium{background:rgba(254,202,87,.08);color:#feca57;border:1px solid rgba(254,202,87,.3)}\n.risk-low{background:rgba(168,216,240,.07);color:var(--muted);border:1px solid rgba(168,216,240,.2)}\n\n/* ── BADGE STATUS ── */\n.badge{font-size:.72rem;padding:1px 6px;border-radius:2px;font-family:var(--sans);font-weight:700;letter-spacing:1px;text-transform:uppercase;white-space:nowrap}\n.badge-honey{background:rgba(127,239,212,.12);color:var(--green);border:1px solid rgba(127,239,212,.28)}\n.badge-threat{background:rgba(255,107,138,.1);color:var(--red);border:1px solid rgba(255,107,138,.26)}\n.badge-ok{background:rgba(168,216,240,.06);color:var(--muted);border:1px solid rgba(168,216,240,.15)}\n\n/* ── TOAST ── */\n#toast-wrap{position:fixed;bottom:16px;right:16px;z-index:9999;display:flex;flex-direction:column;gap:6px;pointer-events:none}\n.toast{background:var(--panel);border:1px solid var(--green);padding:8px 14px;\n  font-family:var(--mono);font-size:.78rem;color:var(--green);\n  box-shadow:0 0 16px rgba(127,239,212,.14);max-width:300px;\n  animation:tIn .3s ease,tOut .3s ease 3.7s forwards}\n.toast.danger{border-color:var(--red);color:var(--red);box-shadow:0 0 16px rgba(255,107,138,.14)}\n@keyframes tIn{from{opacity:0;transform:translateX(14px)}to{opacity:1;transform:translateX(0)}}\n@keyframes tOut{from{opacity:1}to{opacity:0}}\n\n/* ── SCROLLBARS ── */\n::-webkit-scrollbar{width:3px;height:3px}\n::-webkit-scrollbar-track{background:var(--bg)}\n::-webkit-scrollbar-thumb{background:var(--border);border-radius:2px}\n</style>\n\n</head>\n<body>\n\n<div id="sidebar">\n  <div class="sb-logo">\n    <div class="sb-logo-text">COG<span>NI</span>SEC</div>\n    <div class="sb-logo-sub">DECEPTION ENGINE</div>\n  </div>\n  <div class="sb-status"><div class="sb-dot"></div>SYSTEM ACTIVE</div>\n  <nav class="sb-nav"><a href="/" class="active"><span class="nav-icon">🏠</span>Overview<span class="nav-badge" id="s-threats-nav">—</span></a><a href="/traffic"><span class="nav-icon">📡</span>Live Traffic<span class="nav-badge" id="s-feed-nav">—</span></a><a href="/honeypots"><span class="nav-icon">🍯</span>Honeypots<span class="nav-badge" id="s-hp-nav">—</span></a><a href="/attackers"><span class="nav-icon">👾</span>Attackers<span class="nav-badge" id="s-atk-nav">—</span></a></nav>\n  <div class="sb-footer">\n    <div class="sb-clock" id="sb-clock">--:--:--</div>\n    <div class="sb-cmd">$ <span>python attacker.py</span></div>\n  </div>\n</div>\n\n<div id="page">\n\n  <div class="page-hdr">\n    <div>\n      <div class="page-title">// Overview</div>\n      <div class="page-sub">System status, live threat counters and network topology</div>\n    </div>\n    <div class="page-meta" id="last-update">Last update: —</div>\n  </div>\n\n  <!-- STAT ROW -->\n  <div class="stat-row" style="grid-template-columns:repeat(5,1fr)">\n    <div class="stat-card" style="--ca:#a8d8f0;--cb:#7fefd4">\n      <div class="stat-label">// total packets</div>\n      <div class="stat-val" id="s-packets">0</div>\n      <div class="stat-sub">network events processed</div>\n    </div>\n    <div class="stat-card" style="--ca:#ff6b8a;--cb:#ff9f43">\n      <div class="stat-label">// threats detected</div>\n      <div class="stat-val" id="s-threats">0</div>\n      <div class="stat-sub">anomalous sessions flagged</div>\n    </div>\n    <div class="stat-card" style="--ca:#7fefd4;--cb:#a8d8f0">\n      <div class="stat-label">// attackers trapped</div>\n      <div class="stat-val" id="s-redirected">0</div>\n      <div class="stat-sub">successfully honeypotted</div>\n    </div>\n    <div class="stat-card" style="--ca:#b8d4f0;--cb:#fd79a8">\n      <div class="stat-label">// active sessions</div>\n      <div class="stat-val" id="s-active">0</div>\n      <div class="stat-sub">live attacker connections</div>\n    </div>\n    <div class="stat-card" style="--ca:#feca57;--cb:#ff9f43">\n      <div class="stat-label">// deception rate</div>\n      <div class="stat-val" id="s-rate">0%</div>\n      <div class="stat-sub">trap success ratio</div>\n    </div>\n  </div>\n\n  <div style="display:grid;grid-template-columns:1fr 380px;gap:12px;margin-bottom:12px">\n\n    <!-- Network Map -->\n    <div class="panel">\n      <div class="panel-hdr">\n        <div class="panel-title">🌐 Network Deception Topology</div>\n        <div class="panel-badge">LIVE</div>\n      </div>\n      <div class="panel-body panel-nopad" style="height:340px;position:relative">\n        <canvas id="netCanvas" style="width:100%;height:100%"></canvas>\n      </div>\n    </div>\n\n    <!-- Active Attackers -->\n    <div class="panel">\n      <div class="panel-hdr">\n        <div class="panel-title">👾 Active Attackers</div>\n        <div class="panel-badge" id="atk-count">0</div>\n      </div>\n      <div class="panel-body panel-nopad panel-scroll" id="atk-list" style="max-height:340px"></div>\n    </div>\n\n  </div>\n\n  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">\n\n    <!-- Timeline chart -->\n    <div class="panel">\n      <div class="panel-hdr">\n        <div class="panel-title">📈 Activity Timeline</div>\n      </div>\n      <div class="panel-body" style="height:200px;padding:10px">\n        <canvas id="tlChart"></canvas>\n      </div>\n    </div>\n\n    <!-- Category doughnut -->\n    <div class="panel">\n      <div class="panel-hdr">\n        <div class="panel-title">🗂 Attack Category Breakdown</div>\n      </div>\n      <div class="panel-body" style="height:200px;padding:10px">\n        <canvas id="catChart"></canvas>\n      </div>\n    </div>\n\n  </div>\n\n</div>\n\n<div id="toast-wrap"></div>\n<script>\n// ── CLOCK ──\nfunction _clockTick(){\n  const el=document.getElementById(\'sb-clock\');\n  if(el) el.textContent=new Date().toTimeString().slice(0,8);\n}\nsetInterval(_clockTick,500); _clockTick();\n\n// ── STAT BUMP ──\nfunction bump(id,val){\n  const el=document.getElementById(id);\n  if(!el)return;\n  el.textContent=val;\n  el.classList.add(\'bump\');\n  setTimeout(()=>el.classList.remove(\'bump\'),500);\n}\n\n// ── TOAST ──\nfunction toast(msg,danger=false){\n  const c=document.getElementById(\'toast-wrap\');\n  const d=document.createElement(\'div\');\n  d.className=\'toast\'+(danger?\' danger\':\'\');\n  d.textContent=msg;c.appendChild(d);\n  setTimeout(()=>d.remove(),4200);\n}\n\n// ── TECH COLORS ──\nconst TECH_COLORS={\n  port_scan:\'#a8d8f0\',stealth_scan:\'#b8d4f0\',brute_force:\'#ff9f43\',\n  credential_stuff:\'#fd79a8\',vuln_scan:\'#feca57\',exploit_known:\'#ff6b6b\',\n  syn_flood:\'#ff0000\',lateral_move:\'#ff6b8a\',zero_day:\'#fd79a8\',\n  data_exfil:\'#e17055\',unknown:\'#888\'\n};\nconst RISK_COLORS={critical:\'#ff6b8a\',high:\'#ff9f43\',medium:\'#feca57\',low:\'#a8d8f0\'};\n\n// ── ATTACK SUMMARIES ──\nconst ATTACK_SUMMARIES={\n  port_scan:\'Systematically probing ports to map open services. Attacker is in reconnaissance phase building a target profile.\',\n  stealth_scan:\'Low-rate randomised port sweep designed to evade rate-based detection. Indicates a patient, skilled actor.\',\n  brute_force:\'Repeated authentication attempts with credential lists. Attacker is trying to gain direct access.\',\n  credential_stuff:\'Using leaked credential databases across multiple services simultaneously.\',\n  vuln_scan:\'Automated probing for known CVEs and misconfigurations in web-facing services.\',\n  exploit_known:\'Attempting to exploit a known vulnerability. Attacker has identified a specific attack surface.\',\n  syn_flood:\'High-rate SYN packet flood — denial-of-service attempt targeting connection tables.\',\n  lateral_move:\'Post-compromise movement across the network. Attacker already has a foothold.\',\n  zero_day:\'Anomalous payload patterns inconsistent with any known attack signature. Possible novel exploit.\',\n  data_exfil:\'Encoding data in covert channels (DNS/HTTPS tunnelling) to exfiltrate captured information.\',\n  unknown:\'Unclassified traffic pattern with anomalous characteristics.\'\n};\n</script>\n\n<script>\n// ── NETWORK CANVAS ──\nconst NODES={\n  internet:{x:.5,y:.07,label:\'INTERNET\',color:\'#4a7a9b\',r:22},\n  router:{x:.5,y:.28,label:\'ROUTER\',color:\'#a8d8f0\',r:17},\n  fw:{x:.5,y:.5,label:\'FIREWALL\',color:\'#ff9f43\',r:15},\n  real:{x:.18,y:.78,label:\'REAL ASSETS\',color:\'#2a4a64\',r:20},\n  hp1:{x:.62,y:.7,label:\'TRAP-A\',color:\'#7fefd4\',r:14,honey:true},\n  hp2:{x:.82,y:.6,label:\'TRAP-B\',color:\'#7fefd4\',r:14,honey:true},\n  hp3:{x:.76,y:.84,label:\'TRAP-C\',color:\'#7fefd4\',r:13,honey:true},\n};\nconst EDGES=[[\'internet\',\'router\'],[\'router\',\'fw\'],[\'fw\',\'real\'],[\'fw\',\'hp1\'],[\'fw\',\'hp2\'],[\'fw\',\'hp3\']];\nlet nc,nw,nh,pAnim=[];\n\nfunction initNet(){\n  nc=document.getElementById(\'netCanvas\');\n  const wrap=nc.parentElement;\n  nw=nc.width=wrap.clientWidth;nh=nc.height=wrap.clientHeight;\n  requestAnimationFrame(drawNet);\n}\nfunction nxy(id){return[NODES[id].x*nw,NODES[id].y*nh]}\nfunction drawNet(){\n  const ctx=nc.getContext(\'2d\');ctx.clearRect(0,0,nw,nh);\n  EDGES.forEach(([a,b])=>{\n    const[ax,ay]=nxy(a),[bx,by]=nxy(b);\n    ctx.beginPath();ctx.moveTo(ax,ay);ctx.lineTo(bx,by);\n    ctx.strokeStyle=\'rgba(42,74,100,.7)\';ctx.lineWidth=1;ctx.stroke();\n  });\n  pAnim.forEach((p,i)=>{\n    p.t+=0.028;if(p.t>1){pAnim.splice(i,1);return}\n    const[sx,sy]=nxy(p.from),[ex,ey]=nxy(p.to);\n    const x=sx+(ex-sx)*p.t,y=sy+(ey-sy)*p.t;\n    ctx.beginPath();ctx.arc(x,y,4,0,Math.PI*2);\n    ctx.fillStyle=p.color;ctx.shadowColor=p.color;ctx.shadowBlur=10;ctx.fill();ctx.shadowBlur=0;\n  });\n  Object.entries(NODES).forEach(([id,n])=>{\n    const[x,y]=nxy(id);\n    if(n.honey){ctx.beginPath();ctx.arc(x,y,n.r+5,0,Math.PI*2);ctx.fillStyle=\'rgba(127,239,212,.07)\';ctx.fill()}\n    ctx.beginPath();ctx.arc(x,y,n.r,0,Math.PI*2);\n    ctx.fillStyle=n.color+\'20\';ctx.strokeStyle=n.color;ctx.lineWidth=1.5;ctx.fill();ctx.stroke();\n    ctx.fillStyle=\'#fff\';ctx.font=\'bold 7px Share Tech Mono\';ctx.textAlign=\'center\';ctx.textBaseline=\'middle\';\n    const parts=n.label.split(\' \');\n    if(parts.length===1){ctx.fillText(n.label,x,y)}\n    else{ctx.fillText(parts[0],x,y-4);ctx.fillStyle=n.honey?\'#7fefd4\':\'#4a7a9b\';ctx.font=\'6px Share Tech Mono\';ctx.fillText(parts.slice(1).join(\' \'),x,y+4)}\n  });\n  requestAnimationFrame(drawNet);\n}\nfunction animPkt(toHoney,color){\n  const h=[\'hp1\',\'hp2\',\'hp3\'][Math.floor(Math.random()*3)];\n  const path=toHoney?[[\'internet\',\'router\'],[\'router\',\'fw\'],[\'fw\',h]]:[[\'internet\',\'router\'],[\'router\',\'fw\'],[\'fw\',\'real\']];\n  path.forEach(([f,t],i)=>setTimeout(()=>pAnim.push({from:f,to:t,t:0,color:color||\'#a8d8f0\'}),i*280));\n}\n\n// ── CHARTS ──\nlet tlChart,catChart;\nconst tlL=[],tlT=[],tlR=[];\nfunction initCharts(){\n  tlChart=new Chart(document.getElementById(\'tlChart\').getContext(\'2d\'),{\n    type:\'line\',\n    data:{labels:tlL,datasets:[\n      {label:\'Threats\',data:tlT,borderColor:\'#ff6b8a\',backgroundColor:\'rgba(255,107,138,.1)\',tension:.4,pointRadius:0,fill:true},\n      {label:\'Trapped\',data:tlR,borderColor:\'#7fefd4\',backgroundColor:\'rgba(127,239,212,.07)\',tension:.4,pointRadius:0,fill:true},\n    ]},\n    options:{responsive:true,maintainAspectRatio:false,animation:{duration:300},\n      plugins:{legend:{labels:{color:\'#4a7a9b\',font:{family:\'Share Tech Mono\',size:9},boxWidth:8}}},\n      scales:{x:{ticks:{color:\'#4a7a9b\',font:{size:8},maxTicksLimit:8},grid:{color:\'rgba(42,74,100,.3)\'}},\n              y:{ticks:{color:\'#4a7a9b\',font:{size:8}},grid:{color:\'rgba(42,74,100,.3)\'},beginAtZero:true}}}\n  });\n  catChart=new Chart(document.getElementById(\'catChart\').getContext(\'2d\'),{\n    type:\'doughnut\',\n    data:{labels:[],datasets:[{data:[],\n      backgroundColor:[\'#ff6b8a\',\'#ff9f43\',\'#feca57\',\'#a8d8f0\',\'#b8d4f0\',\'#7fefd4\',\'#fd79a8\',\'#e17055\'],\n      borderWidth:1,borderColor:\'#152030\'}]},\n    options:{responsive:true,maintainAspectRatio:false,\n      plugins:{legend:{position:\'right\',labels:{color:\'#4a7a9b\',font:{family:\'Share Tech Mono\',size:9},boxWidth:10,padding:6}}}}\n  });\n}\n\n// ── ATTACKER LIST ──\nfunction renderAttackers(list){\n  const el=document.getElementById(\'atk-list\');\n  if(!list.length){el.innerHTML=\'<div style="padding:20px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.8rem">NO ACTIVE SESSIONS</div>\';return}\n  el.innerHTML=\'\';\n  list.forEach(a=>{\n    const d=document.createElement(\'div\');\n    d.style.cssText=\'padding:10px 12px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px\';\n    const pips=[1,2,3,4].map(i=>`<div style="width:5px;height:5px;border-radius:1px;background:${i<=a.skill?\'var(--red)\':\'var(--border)\'}"></div>`).join(\'\');\n    d.innerHTML=`<div style="font-family:var(--mono);font-size:.85rem;color:var(--accent);flex:1">${a.ip}</div>\n      <div><div style="font-size:.68rem;color:var(--muted)">${a.profile}</div>\n      <div style="display:flex;gap:2px;margin-top:3px">${pips}</div></div>`;\n    el.appendChild(d);\n  });\n}\n\n// ── POLL ──\nasync function poll(){\n  try{\n    const d=await fetch(\'/api/state\').then(r=>r.json());\n    const s=d.stats;\n    bump(\'s-packets\',s.total_packets);bump(\'s-threats\',s.threats_detected);\n    bump(\'s-redirected\',s.attackers_redirected);bump(\'s-active\',s.active_attackers.length);\n    const rate=s.threats_detected>0?Math.round(s.attackers_redirected/s.threats_detected*100):0;\n    bump(\'s-rate\',rate+\'%\');\n    document.getElementById(\'atk-count\').textContent=s.active_attackers.length;\n    document.getElementById(\'last-update\').textContent=\'Last update: \'+new Date().toTimeString().slice(0,8);\n    renderAttackers(s.active_attackers);\n    // Update sidebar badges\n    const sn=document.getElementById(\'s-threats-nav\');if(sn)sn.textContent=s.threats_detected;\n    // Timeline\n    if(d.timeline&&d.timeline.length){\n      const last=d.timeline[d.timeline.length-1];\n      if(tlL.length>40){tlL.shift();tlT.shift();tlR.shift()}\n      tlL.push(last.t);tlT.push(last.threats);tlR.push(last.redirected);\n      tlChart.update(\'none\');\n    }\n    // Category\n    if(d.category_counts&&Object.keys(d.category_counts).length){\n      catChart.data.labels=Object.keys(d.category_counts);\n      catChart.data.datasets[0].data=Object.values(d.category_counts);\n      catChart.update(\'none\');\n    }\n  }catch(e){}\n}\n\n// ── SSE ──\nfunction connectSSE(){\n  const es=new EventSource(\'/api/stream\');\n  es.onmessage=e=>{\n    try{\n      const msg=JSON.parse(e.data);\n      if(msg.kind===\'packet\') animPkt(msg.data.redirected,TECH_COLORS[msg.data.technique]);\n      else if(msg.kind===\'new_attacker\') toast(\'⚠ NEW ATTACKER: \'+msg.data.ip+\' [\'+msg.data.profile+\']\',true);\n      else if(msg.kind===\'redirect\') toast(\'🎯 TRAPPED: \'+msg.data.attacker_ip+\' → \'+msg.data.service);\n    }catch(_){}\n  };\n  es.onerror=()=>{setTimeout(connectSSE,3000);es.close()};\n}\n\nwindow.addEventListener(\'DOMContentLoaded\',()=>{\n  initNet(); initCharts(); connectSSE();\n  poll(); setInterval(poll,3000);\n});\n</script>\n</body></html>', 'traffic': '<!DOCTYPE html>\n<html lang="en">\n<head>\n<title>COGNISEC — Live Traffic</title>\n\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<link href="https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Rajdhani:wght@400;600;700&family=Exo+2:wght@300;700;900&display=swap" rel="stylesheet">\n<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>\n<style>\n:root{\n  --bg:#0d1117;--bg2:#111b24;--panel:#152030;--panel2:#182535;\n  --border:#2a4a64;--accent:#a8d8f0;--green:#7fefd4;--orange:#ff9f43;\n  --red:#ff6b8a;--purple:#b8d4f0;--muted:#4a7a9b;--text:#e0f0f8;\n  --mono:\'Share Tech Mono\',monospace;--sans:\'Rajdhani\',sans-serif;\n}\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\nhtml{font-size:16px;scroll-behavior:smooth}\nbody{background:var(--bg);color:var(--text);font-family:var(--sans);min-height:100vh;overflow-x:hidden;font-size:1rem}\nbody::before{content:\'\';position:fixed;inset:0;\n  background-image:linear-gradient(rgba(168,216,240,.022) 1px,transparent 1px),\n  linear-gradient(90deg,rgba(168,216,240,.022) 1px,transparent 1px);\n  background-size:44px 44px;pointer-events:none;z-index:0}\nbody::after{content:\'\';position:fixed;inset:0;\n  background:repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,.05) 3px,rgba(0,0,0,.05) 4px);\n  pointer-events:none;z-index:9998}\n\n/* ── SIDEBAR NAV ── */\n#sidebar{\n  position:fixed;left:0;top:0;bottom:0;width:200px;\n  background:rgba(13,17,23,.97);border-right:1px solid var(--border);\n  display:flex;flex-direction:column;z-index:1000;\n  backdrop-filter:blur(12px);\n}\n.sb-logo{padding:18px 16px 14px;border-bottom:1px solid var(--border)}\n.sb-logo-text{font-family:var(--mono);font-size:1.1rem;color:var(--accent);\n  letter-spacing:4px;text-shadow:0 0 14px rgba(168,216,240,.45)}\n.sb-logo-text span{color:var(--green)}\n.sb-logo-sub{font-family:var(--mono);font-size:.72rem;color:var(--muted);\n  letter-spacing:2px;margin-top:3px}\n.sb-status{display:flex;align-items:center;gap:6px;padding:10px 16px;\n  border-bottom:1px solid var(--border);font-family:var(--mono);font-size:.75rem;color:var(--green)}\n.sb-dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:pulse 1.5s infinite}\n@keyframes pulse{0%,100%{opacity:1;box-shadow:0 0 6px var(--green)}50%{opacity:.3;box-shadow:none}}\n.sb-nav{flex:1;padding:10px 0;overflow-y:auto}\n.sb-nav a{\n  display:flex;align-items:center;gap:10px;\n  padding:10px 16px;text-decoration:none;\n  font-family:var(--sans);font-size:.92rem;font-weight:600;\n  letter-spacing:1.5px;text-transform:uppercase;\n  color:var(--muted);border-left:2px solid transparent;\n  transition:all .2s;\n}\n.sb-nav a:hover{color:var(--text);background:rgba(168,216,240,.04);border-left-color:var(--muted)}\n.sb-nav a.active{color:var(--accent);background:rgba(168,216,240,.06);border-left-color:var(--accent)}\n.sb-nav a .nav-icon{font-size:1rem;width:18px;text-align:center}\n.sb-nav .nav-badge{margin-left:auto;font-family:var(--mono);font-size:.68rem;\n  padding:1px 5px;border:1px solid rgba(168,216,240,.2);color:var(--muted)}\n.sb-nav a.active .nav-badge{border-color:rgba(168,216,240,.4);color:var(--accent)}\n.sb-footer{padding:12px 16px;border-top:1px solid var(--border)}\n.sb-clock{font-family:var(--mono);font-size:.78rem;color:var(--muted)}\n.sb-cmd{font-family:var(--mono);font-size:.72rem;color:rgba(58,106,132,.5);\n  margin-top:6px;line-height:1.6}\n.sb-cmd span{color:var(--accent)}\n\n/* ── PAGE WRAPPER ── */\n#page{margin-left:200px;position:relative;z-index:1;padding:16px;min-height:100vh}\n\n/* ── PAGE HEADER ── */\n.page-hdr{margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;justify-content:space-between}\n.page-title{font-family:var(--mono);font-size:1.2rem;color:var(--accent);letter-spacing:3px;text-transform:uppercase}\n.page-sub{font-size:.85rem;color:var(--muted);margin-top:3px}\n.page-meta{font-family:var(--mono);font-size:.75rem;color:var(--muted)}\n\n/* ── STAT CARDS ── */\n.stat-row{display:grid;gap:10px;margin-bottom:16px}\n.stat-card{background:var(--panel);border:1px solid var(--border);padding:14px 18px;position:relative;overflow:hidden}\n.stat-card::before{content:\'\';position:absolute;top:0;left:0;width:100%;height:2px;\n  background:linear-gradient(90deg,var(--ca,var(--accent)),var(--cb,var(--green)))}\n.stat-label{font-family:var(--mono);font-size:.72rem;letter-spacing:2px;color:var(--muted);\n  text-transform:uppercase;margin-bottom:6px}\n.stat-val{font-family:var(--mono);font-size:2.2rem;color:#fff;line-height:1;transition:all .3s}\n.stat-val.bump{color:var(--accent);text-shadow:0 0 18px rgba(168,216,240,.5)}\n.stat-sub{font-size:.75rem;color:var(--muted);margin-top:3px}\n\n/* ── PANEL ── */\n.panel{background:var(--panel);border:1px solid var(--border);display:flex;flex-direction:column;overflow:hidden}\n.panel-hdr{padding:9px 13px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;gap:8px;flex-shrink:0}\n.panel-title{font-family:var(--mono);font-size:.78rem;letter-spacing:2px;text-transform:uppercase;color:var(--accent)}\n.panel-badge{margin-left:auto;font-family:var(--mono);font-size:.72rem;\n  padding:2px 8px;border:1px solid rgba(168,216,240,.22);color:var(--muted)}\n.panel-body{flex:1;overflow:hidden;padding:12px}\n.panel-scroll{overflow-y:auto}\n.panel-nopad{padding:0}\n\n/* ── RISK BADGES ── */\n.risk{font-size:.72rem;padding:1px 5px;border-radius:2px;text-transform:uppercase;font-weight:700;letter-spacing:1px}\n.risk-critical{background:rgba(255,107,138,.14);color:var(--red);border:1px solid rgba(255,107,138,.3)}\n.risk-high{background:rgba(255,159,67,.1);color:var(--orange);border:1px solid rgba(255,159,67,.3)}\n.risk-medium{background:rgba(254,202,87,.08);color:#feca57;border:1px solid rgba(254,202,87,.3)}\n.risk-low{background:rgba(168,216,240,.07);color:var(--muted);border:1px solid rgba(168,216,240,.2)}\n\n/* ── BADGE STATUS ── */\n.badge{font-size:.72rem;padding:1px 6px;border-radius:2px;font-family:var(--sans);font-weight:700;letter-spacing:1px;text-transform:uppercase;white-space:nowrap}\n.badge-honey{background:rgba(127,239,212,.12);color:var(--green);border:1px solid rgba(127,239,212,.28)}\n.badge-threat{background:rgba(255,107,138,.1);color:var(--red);border:1px solid rgba(255,107,138,.26)}\n.badge-ok{background:rgba(168,216,240,.06);color:var(--muted);border:1px solid rgba(168,216,240,.15)}\n\n/* ── TOAST ── */\n#toast-wrap{position:fixed;bottom:16px;right:16px;z-index:9999;display:flex;flex-direction:column;gap:6px;pointer-events:none}\n.toast{background:var(--panel);border:1px solid var(--green);padding:8px 14px;\n  font-family:var(--mono);font-size:.78rem;color:var(--green);\n  box-shadow:0 0 16px rgba(127,239,212,.14);max-width:300px;\n  animation:tIn .3s ease,tOut .3s ease 3.7s forwards}\n.toast.danger{border-color:var(--red);color:var(--red);box-shadow:0 0 16px rgba(255,107,138,.14)}\n@keyframes tIn{from{opacity:0;transform:translateX(14px)}to{opacity:1;transform:translateX(0)}}\n@keyframes tOut{from{opacity:1}to{opacity:0}}\n\n/* ── SCROLLBARS ── */\n::-webkit-scrollbar{width:3px;height:3px}\n::-webkit-scrollbar-track{background:var(--bg)}\n::-webkit-scrollbar-thumb{background:var(--border);border-radius:2px}\n</style>\n\n<style>\n/* ── PACKET TABLE ── */\n.pkt-table{{width:100%;border-collapse:collapse;table-layout:fixed}}\n.pkt-table thead{{position:sticky;top:0;z-index:10;background:var(--bg2)}}\n.pkt-table thead tr{{border-bottom:2px solid var(--border)}}\n.pkt-table th{{\n  font-family:var(--mono);font-size:.72rem;letter-spacing:2px;text-transform:uppercase;\n  color:var(--muted);padding:14px 14px;text-align:left;white-space:nowrap;\n  background:var(--bg2);border-bottom:2px solid var(--border);\n}}\n.pkt-row{{cursor:pointer;border-bottom:1px solid rgba(42,74,100,.4);transition:background .12s;animation:fadeRow .25s ease}}\n.pkt-row:hover{{background:rgba(168,216,240,.05)}}\n.pkt-row.selected{{background:rgba(168,216,240,.08);outline:1px solid rgba(168,216,240,.3)}}\n.pkt-row.redirected{{border-left:3px solid var(--green)}}\n.pkt-row.is-threat{{border-left:3px solid var(--red)}}\n@keyframes fadeRow{{from{{opacity:0;background:rgba(168,216,240,.07)}}to{{opacity:1}}}}\n.pkt-table td{{\n  font-family:var(--mono);font-size:.82rem;padding:12px 14px;\n  vertical-align:middle;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;\n}}\n/* ── per-column widths (% so header+body always match) ── */\n.pkt-table .col-ts   {{width:9%}}\n.pkt-table .col-ip   {{width:16%}}\n.pkt-table .col-port {{width:6%}}\n.pkt-table .col-svc  {{width:10%}}\n.pkt-table .col-proto{{width:6%}}\n.pkt-table .col-tech {{width:14%}}\n.pkt-table .col-score{{width:7%}}\n.pkt-table .col-stat {{width:10%}}\n.td-ts{{color:var(--muted)}}\n.td-ip{{color:var(--accent)}}\n.td-port{{color:var(--text)}}\n.td-svc{{color:var(--muted);font-size:.78rem}}\n.td-score{{}}\n\n/* ── DETAIL PANEL ── */\n#detail-panel{{\n  position:fixed;right:0;top:0;bottom:0;width:420px;\n  background:var(--bg2);border-left:1px solid var(--border);\n  z-index:500;transform:translateX(100%);\n  transition:transform .3s cubic-bezier(.4,0,.2,1);\n  display:flex;flex-direction:column;overflow:hidden;\n}}\n#detail-panel.open{{transform:translateX(0)}}\n#dp-hdr{{padding:16px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px}}\n#dp-title{{font-family:var(--mono);font-size:.92rem;color:var(--accent);letter-spacing:2px;flex:1}}\n#dp-close{{background:transparent;border:1px solid var(--border);color:var(--muted);\n  font-family:var(--mono);font-size:.8rem;padding:6px 12px;cursor:pointer;transition:all .2s}}\n#dp-close:hover{{border-color:var(--red);color:var(--red)}}\n#dp-body{{flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:14px}}\n\n.dp-section{{}}\n.dp-section-title{{font-family:var(--mono);font-size:.72rem;letter-spacing:2px;text-transform:uppercase;\n  color:var(--muted);margin-bottom:8px;display:flex;align-items:center;gap:8px}}\n.dp-section-title::before{{content:\'//\';color:rgba(58,106,132,.5)}}\n.dp-section-title::after{{content:\'\';flex:1;height:1px;background:var(--border)}}\n\n.dp-grid{{display:grid;grid-template-columns:1fr 1fr;gap:8px}}\n.dp-field{{background:var(--panel);border:1px solid var(--border);padding:10px 13px}}\n.dp-field-label{{font-family:var(--mono);font-size:.65rem;letter-spacing:1.5px;text-transform:uppercase;\n  color:var(--muted);margin-bottom:5px}}\n.dp-field-val{{font-family:var(--mono);font-size:.88rem;color:#fff;word-break:break-all}}\n.dp-field-val.accent{{color:var(--accent)}}\n.dp-field-val.green{{color:var(--green)}}\n.dp-field-val.red{{color:var(--red)}}\n\n.dp-score-bar{{height:6px;background:var(--bg);border:1px solid var(--border);border-radius:1px;overflow:hidden;margin-top:6px}}\n.dp-score-fill{{height:100%;border-radius:1px;transition:width .6s ease}}\n\n.dp-summary{{background:var(--panel);border:1px solid var(--border);border-left:2px solid var(--accent);\n  padding:13px;font-size:.88rem;line-height:1.75;color:var(--text)}}\n\n.dp-honeypot-box{{background:rgba(127,239,212,.06);border:1px solid rgba(127,239,212,.25);padding:13px}}\n.dp-honeypot-box .dp-field-label{{color:var(--green)}}\n\n.dp-empty{{padding:40px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.82rem;line-height:2}}\n\n/* Shrink page when panel open */\nbody.panel-open #page{{margin-right:420px;transition:margin-right .3s}}\n</style>\n</head>\n<body>\n\n<div id="sidebar">\n  <div class="sb-logo">\n    <div class="sb-logo-text">COG<span>NI</span>SEC</div>\n    <div class="sb-logo-sub">DECEPTION ENGINE</div>\n  </div>\n  <div class="sb-status"><div class="sb-dot"></div>SYSTEM ACTIVE</div>\n  <nav class="sb-nav"><a href="/"><span class="nav-icon">🏠</span>Overview<span class="nav-badge" id="s-threats-nav">—</span></a><a href="/traffic" class="active"><span class="nav-icon">📡</span>Live Traffic<span class="nav-badge" id="s-feed-nav">—</span></a><a href="/honeypots"><span class="nav-icon">🍯</span>Honeypots<span class="nav-badge" id="s-hp-nav">—</span></a><a href="/attackers"><span class="nav-icon">👾</span>Attackers<span class="nav-badge" id="s-atk-nav">—</span></a></nav>\n  <div class="sb-footer">\n    <div class="sb-clock" id="sb-clock">--:--:--</div>\n    <div class="sb-cmd">$ <span>python attacker.py</span></div>\n  </div>\n</div>\n\n<div id="page">\n  <div class="page-hdr">\n    <div>\n      <div class="page-title">// Live Traffic</div>\n      <div class="page-sub">Real-time packet feed — click any event to inspect it</div>\n    </div>\n    <div style="display:flex;align-items:center;gap:10px">\n      <div style="font-family:var(--mono);font-size:.62rem;color:var(--muted)" id="feed-meta">0 events</div>\n      <button onclick="clearFeed()" style="background:transparent;border:1px solid var(--border);color:var(--muted);font-family:var(--mono);font-size:.6rem;padding:4px 10px;cursor:pointer">CLEAR</button>\n    </div>\n  </div>\n\n  <!-- STAT ROW -->\n  <div class="stat-row" style="grid-template-columns:repeat(4,1fr);margin-bottom:14px">\n    <div class="stat-card" style="--ca:#a8d8f0;--cb:#7fefd4">\n      <div class="stat-label">// total packets</div>\n      <div class="stat-val" id="s-packets">0</div></div>\n    <div class="stat-card" style="--ca:#ff6b8a;--cb:#ff9f43">\n      <div class="stat-label">// threats</div>\n      <div class="stat-val" id="s-threats">0</div></div>\n    <div class="stat-card" style="--ca:#7fefd4;--cb:#a8d8f0">\n      <div class="stat-label">// honeypotted</div>\n      <div class="stat-val" id="s-redirected">0</div></div>\n    <div class="stat-card" style="--ca:#b8d4f0;--cb:#fd79a8">\n      <div class="stat-label">// benign passed</div>\n      <div class="stat-val" id="s-benign">0</div></div>\n  </div>\n\n  <!-- TRAFFIC TABLE -->\n  <div class="panel" style="flex:1">\n    <div class="panel-hdr">\n      <div class="panel-title">📡 Packet Stream</div>\n      <div style="display:flex;align-items:center;gap:8px;margin-left:auto">\n        <label style="font-family:var(--mono);font-size:.6rem;color:var(--muted);display:flex;align-items:center;gap:5px">\n          <input type="checkbox" id="filter-threats" onchange="applyFilter()"> Threats only\n        </label>\n        <label style="font-family:var(--mono);font-size:.6rem;color:var(--muted);display:flex;align-items:center;gap:5px">\n          <input type="checkbox" id="filter-honey" onchange="applyFilter()"> Honeypotted only\n        </label>\n        <div class="panel-badge" id="visible-count">0 shown</div>\n      </div>\n    </div>\n    <div class="panel-body panel-nopad" style="overflow-y:auto;max-height:calc(100vh - 310px)">\n      <table class="pkt-table" id="pkt-tbody-wrap">\n        <colgroup>\n          <col class="col-ts">\n          <col class="col-ip">\n          <col class="col-port">\n          <col class="col-svc">\n          <col class="col-proto">\n          <col class="col-tech">\n          <col class="col-score">\n          <col class="col-stat">\n        </colgroup>\n        <thead>\n          <tr>\n            <th class="col-ts">TIME</th>\n            <th class="col-ip">SOURCE IP</th>\n            <th class="col-port">PORT</th>\n            <th class="col-svc">SERVICE</th>\n            <th class="col-proto">PROTO</th>\n            <th class="col-tech">TECHNIQUE</th>\n            <th class="col-score">SCORE</th>\n            <th class="col-stat">STATUS</th>\n          </tr>\n        </thead>\n        <tbody id="pkt-tbody"></tbody>\n      </table>\n    </div>\n  </div>\n\n</div>\n\n<!-- DETAIL PANEL -->\n<div id="detail-panel">\n  <div id="dp-hdr">\n    <div id="dp-title">EVENT DETAIL</div>\n    <button id="dp-close" onclick="closeDetail()">✕ CLOSE</button>\n  </div>\n  <div id="dp-body">\n    <div class="dp-empty">← Select an event from the feed<br>to inspect it here</div>\n  </div>\n</div>\n\n\n<div id="toast-wrap"></div>\n<script>\n// ── CLOCK ──\nfunction _clockTick(){\n  const el=document.getElementById(\'sb-clock\');\n  if(el) el.textContent=new Date().toTimeString().slice(0,8);\n}\nsetInterval(_clockTick,500); _clockTick();\n\n// ── STAT BUMP ──\nfunction bump(id,val){\n  const el=document.getElementById(id);\n  if(!el)return;\n  el.textContent=val;\n  el.classList.add(\'bump\');\n  setTimeout(()=>el.classList.remove(\'bump\'),500);\n}\n\n// ── TOAST ──\nfunction toast(msg,danger=false){\n  const c=document.getElementById(\'toast-wrap\');\n  const d=document.createElement(\'div\');\n  d.className=\'toast\'+(danger?\' danger\':\'\');\n  d.textContent=msg;c.appendChild(d);\n  setTimeout(()=>d.remove(),4200);\n}\n\n// ── TECH COLORS ──\nconst TECH_COLORS={\n  port_scan:\'#a8d8f0\',stealth_scan:\'#b8d4f0\',brute_force:\'#ff9f43\',\n  credential_stuff:\'#fd79a8\',vuln_scan:\'#feca57\',exploit_known:\'#ff6b6b\',\n  syn_flood:\'#ff0000\',lateral_move:\'#ff6b8a\',zero_day:\'#fd79a8\',\n  data_exfil:\'#e17055\',unknown:\'#888\'\n};\nconst RISK_COLORS={critical:\'#ff6b8a\',high:\'#ff9f43\',medium:\'#feca57\',low:\'#a8d8f0\'};\n\n// ── ATTACK SUMMARIES ──\nconst ATTACK_SUMMARIES={\n  port_scan:\'Systematically probing ports to map open services. Attacker is in reconnaissance phase building a target profile.\',\n  stealth_scan:\'Low-rate randomised port sweep designed to evade rate-based detection. Indicates a patient, skilled actor.\',\n  brute_force:\'Repeated authentication attempts with credential lists. Attacker is trying to gain direct access.\',\n  credential_stuff:\'Using leaked credential databases across multiple services simultaneously.\',\n  vuln_scan:\'Automated probing for known CVEs and misconfigurations in web-facing services.\',\n  exploit_known:\'Attempting to exploit a known vulnerability. Attacker has identified a specific attack surface.\',\n  syn_flood:\'High-rate SYN packet flood — denial-of-service attempt targeting connection tables.\',\n  lateral_move:\'Post-compromise movement across the network. Attacker already has a foothold.\',\n  zero_day:\'Anomalous payload patterns inconsistent with any known attack signature. Possible novel exploit.\',\n  data_exfil:\'Encoding data in covert channels (DNS/HTTPS tunnelling) to exfiltrate captured information.\',\n  unknown:\'Unclassified traffic pattern with anomalous characteristics.\'\n};\n</script>\n\n<script>\nlet allEvents=[], selectedId=null, filterThreats=false, filterHoney=false;\n\n// ── FILTER ──\nfunction applyFilter(){\n  filterThreats=document.getElementById(\'filter-threats\').checked;\n  filterHoney=document.getElementById(\'filter-honey\').checked;\n  renderTable();\n}\n\n// ── CLEAR ──\nfunction clearFeed(){ allEvents=[]; selectedId=null; renderTable(); closeDetail(); }\n\n// ── ADD EVENT ──\nfunction addEvent(ev){\n  ev._id = Date.now()+Math.random();\n  allEvents.unshift(ev);\n  if(allEvents.length>300) allEvents=allEvents.slice(0,300);\n  renderTable();\n  document.getElementById(\'feed-meta\').textContent=allEvents.length+\' events\';\n}\n\n// ── RENDER TABLE ──\nfunction renderTable(){\n  const tbody=document.getElementById(\'pkt-tbody\');\n  let visible=allEvents;\n  if(filterThreats) visible=visible.filter(e=>e.threat_score>=45||e.redirected);\n  if(filterHoney)   visible=visible.filter(e=>e.redirected);\n\n  tbody.innerHTML=\'\';\n  visible.forEach(ev=>{\n    const sc=ev.threat_score||0;\n    const tc=TECH_COLORS[ev.technique]||\'#888\';\n    const scColor=sc>=70?\'var(--red)\':sc>=45?\'var(--orange)\':\'var(--muted)\';\n    const badge=ev.redirected\n      ?\'<span class="badge badge-honey">HONEYPOT</span>\'\n      :sc>=45?\'<span class="badge badge-threat">THREAT</span>\'\n      :\'<span class="badge badge-ok">PASS</span>\';\n    const tr=document.createElement(\'tr\');\n    tr.className=\'pkt-row\'+(ev.redirected?\' redirected\':sc>=45?\' is-threat\':\'\')+(ev._id===selectedId?\' selected\':\'\');\n    tr.dataset.id=ev._id;\n    tr.onclick=()=>openDetail(ev);\n    tr.innerHTML=`<td class="td-ts col-ts">${ev.ts}</td>\n      <td class="td-ip col-ip">${ev.src_ip}</td>\n      <td class="td-port col-port">${ev.dst_port}</td>\n      <td class="td-svc col-svc">${ev.service||\'—\'}</td>\n      <td class="col-proto" style="color:var(--muted);font-size:.78rem">${ev.protocol||\'TCP\'}</td>\n      <td class="col-tech"><span style="color:${tc};font-size:.76rem;padding:2px 6px;border:1px solid ${tc}44">${ev.technique||\'—\'}</span></td>\n      <td class="col-score" style="color:${scColor}">${sc}</td>\n      <td class="col-stat">${badge}</td>`;\n    tbody.appendChild(tr);\n  });\n  document.getElementById(\'visible-count\').textContent=visible.length+\' shown\';\n}\n\n// ── OPEN DETAIL ──\nfunction openDetail(ev){\n  selectedId=ev._id;\n  renderTable();\n  const sc=ev.threat_score||0;\n  const scColor=sc>=70?\'#ff6b8a\':sc>=45?\'#ff9f43\':\'#7fefd4\';\n  const scLabel=sc>=70?\'CRITICAL\':sc>=45?\'HIGH THREAT\':sc>=20?\'MEDIUM\':\'BENIGN\';\n  const isHoney=!!ev.redirected;\n  const summary=ATTACK_SUMMARIES[ev.technique]||ATTACK_SUMMARIES[\'unknown\'];\n  const tc=TECH_COLORS[ev.technique]||\'#888\';\n\n  let honeypotSection=\'\';\n  if(isHoney){\n    honeypotSection=`\n    <div class="dp-section">\n      <div class="dp-section-title">Deception Outcome</div>\n      <div class="dp-honeypot-box">\n        <div class="dp-field-label">Attacker Redirected To</div>\n        <div class="dp-field-val green" style="font-size:.9rem;margin-bottom:8px">🍯 ${ev.service||\'Honeypot\'} on port ${ev.dst_port}</div>\n        <div class="dp-field-label" style="margin-top:8px">Fake Banner Presented</div>\n        <div class="dp-field-val" style="color:var(--text);font-size:.7rem">${ev.banner||\'Deceptive service banner\'}</div>\n        <div style="margin-top:8px;font-size:.68rem;color:var(--green);line-height:1.6">\n          ✓ Attacker believes they connected to a real service.<br>\n          ✓ All interaction is being logged.<br>\n          ✓ Real assets remain untouched.\n        </div>\n      </div>\n    </div>`;\n  }\n\n  document.getElementById(\'dp-body\').innerHTML=`\n    <div class="dp-section">\n      <div class="dp-section-title">Source Intelligence</div>\n      <div class="dp-grid">\n        <div class="dp-field">\n          <div class="dp-field-label">Source IP</div>\n          <div class="dp-field-val accent">${ev.src_ip}</div>\n        </div>\n        <div class="dp-field">\n          <div class="dp-field-label">Timestamp</div>\n          <div class="dp-field-val">${ev.ts}</div>\n        </div>\n        <div class="dp-field">\n          <div class="dp-field-label">Protocol</div>\n          <div class="dp-field-val">${ev.protocol||\'TCP\'}</div>\n        </div>\n        <div class="dp-field">\n          <div class="dp-field-label">Target Port</div>\n          <div class="dp-field-val">${ev.dst_port} <span style="color:var(--muted);font-size:.65rem">(${ev.service||\'unknown\'})</span></div>\n        </div>\n      </div>\n    </div>\n\n    <div class="dp-section">\n      <div class="dp-section-title">Attack Pattern Detected</div>\n      <div class="dp-field" style="margin-bottom:8px">\n        <div class="dp-field-label">Technique</div>\n        <div class="dp-field-val" style="color:${tc};font-size:.9rem">${(ev.technique||\'unknown\').replace(/_/g,\' \').toUpperCase()}</div>\n      </div>\n      <div class="dp-summary">${summary}</div>\n    </div>\n\n    <div class="dp-section">\n      <div class="dp-section-title">Threat Score</div>\n      <div class="dp-field">\n        <div style="display:flex;justify-content:space-between;align-items:center">\n          <div class="dp-field-val" style="color:${scColor};font-size:1.6rem">${sc}</div>\n          <div style="font-family:var(--mono);font-size:.65rem;color:${scColor}">${scLabel}</div>\n        </div>\n        <div class="dp-score-bar">\n          <div class="dp-score-fill" style="width:${sc}%;background:${scColor}"></div>\n        </div>\n        <div style="display:grid;grid-template-columns:1fr 1fr;gap:4px;margin-top:8px">\n          <div style="font-family:var(--mono);font-size:.6rem;color:var(--muted)">Entropy: <span style="color:var(--text)">${ev.entropy!=null?ev.entropy.toFixed(2):\'—\'}</span></div>\n          <div style="font-family:var(--mono);font-size:.6rem;color:var(--muted)">Payload: <span style="color:var(--text)">${ev.payload_size||\'—\'} B</span></div>\n        </div>\n      </div>\n    </div>\n\n    ${honeypotSection}\n\n    <div class="dp-section">\n      <div class="dp-section-title">Analyst Summary</div>\n      <div class="dp-summary" style="border-left-color:${isHoney?\'var(--green)\':sc>=45?\'var(--red)\':\'var(--muted)\'}">\n        ${isHoney\n          ? `<strong style="color:var(--green)">✓ DECEPTION SUCCESSFUL.</strong> The attacker at <strong>${ev.src_ip}</strong> was silently redirected to a honeypot on port ${ev.dst_port}. They are interacting with a fake <strong>${ev.service||\'service\'}</strong> while real infrastructure remains untouched. All session data is being captured for threat intelligence.`\n          : sc>=45\n          ? `<strong style="color:var(--red)">⚠ THREAT DETECTED.</strong> Anomalous traffic from <strong>${ev.src_ip}</strong> was flagged with score ${sc}/100. Technique: <strong>${(ev.technique||\'\').replace(/_/g,\' \')}</strong>. The engine is monitoring for escalation.`\n          : `<strong style="color:var(--muted)">✓ BENIGN TRAFFIC.</strong> Traffic from <strong>${ev.src_ip}</strong> shows normal characteristics. Threat score: ${sc}/100. No deceptive action required.`\n        }\n      </div>\n    </div>\n  `;\n\n  document.getElementById(\'detail-panel\').classList.add(\'open\');\n  document.body.classList.add(\'panel-open\');\n  document.getElementById(\'dp-title\').textContent=\'EVENT · \'+ev.ts;\n}\n\nfunction closeDetail(){\n  document.getElementById(\'detail-panel\').classList.remove(\'open\');\n  document.body.classList.remove(\'panel-open\');\n  selectedId=null;\n  renderTable();\n}\n\n// ── POLL STATS ──\nasync function poll(){\n  try{\n    const d=await fetch(\'/api/state\').then(r=>r.json());\n    const s=d.stats;\n    bump(\'s-packets\',s.total_packets);bump(\'s-threats\',s.threats_detected);\n    bump(\'s-redirected\',s.attackers_redirected);bump(\'s-benign\',s.benign_passed);\n    const sn=document.getElementById(\'s-feed-nav\');if(sn)sn.textContent=allEvents.length;\n  }catch(e){}\n}\n\n// ── SSE ──\nfunction connectSSE(){\n  const es=new EventSource(\'/api/stream\');\n  es.onmessage=e=>{\n    try{\n      const msg=JSON.parse(e.data);\n      if(msg.kind===\'packet\'){\n        // Main attack/threat packet — add directly\n        addEvent(Object.assign({},msg.data));\n      } else if(msg.kind===\'benign_pkt\'){\n        // Background benign traffic — add with score 0\n        addEvent(Object.assign({threat_score:0,redirected:false,technique:\'benign\',protocol:\'TCP\'},msg.data));\n      } else if(msg.kind===\'redirect\'){\n        // Patch the most recent matching src_ip event with honeypot detail\n        const rec=msg.data;\n        const match=allEvents.find(ev=>ev.src_ip===rec.attacker_ip);\n        if(match){\n          match.banner=rec.banner;\n          match.service=rec.service||match.service;\n          match.redirected=true;\n          match.risk=rec.risk;\n          renderTable();\n        }\n        toast(\'🎯 TRAPPED: \'+rec.attacker_ip+\' → \'+(rec.service||\'honeypot\'));\n      } else if(msg.kind===\'new_attacker\'){\n        toast(\'⚠ NEW ATTACKER: \'+msg.data.ip,true);\n      }\n    }catch(_){}\n  };\n  es.onerror=()=>{setTimeout(connectSSE,3000);es.close()};\n}\n\nwindow.addEventListener(\'DOMContentLoaded\',async()=>{\n  connectSSE(); poll(); setInterval(poll,4000);\n  // Pre-populate feed from server-side recent redirections on page load\n  try{\n    const d=await fetch(\'/api/state\').then(r=>r.json());\n    (d.recent_redirections||[]).slice().reverse().forEach(rec=>{\n      addEvent({\n        src_ip: rec.attacker_ip,\n        dst_port: rec.to_port,\n        service: rec.service,\n        banner: rec.banner,\n        technique: rec.technique||\'unknown\',\n        protocol: \'TCP\',\n        threat_score: 80,\n        redirected: true,\n        risk: rec.risk,\n        ts: rec.ts,\n        entropy: null,\n        payload_size: null,\n      });\n    });\n  }catch(e){}\n});\n</script>\n</body></html>', 'honeypots': '<!DOCTYPE html>\n<html lang="en">\n<head>\n<title>COGNISEC — Honeypots</title>\n\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<link href="https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Rajdhani:wght@400;600;700&family=Exo+2:wght@300;700;900&display=swap" rel="stylesheet">\n<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>\n<style>\n:root{\n  --bg:#0d1117;--bg2:#111b24;--panel:#152030;--panel2:#182535;\n  --border:#2a4a64;--accent:#a8d8f0;--green:#7fefd4;--orange:#ff9f43;\n  --red:#ff6b8a;--purple:#b8d4f0;--muted:#4a7a9b;--text:#e0f0f8;\n  --mono:\'Share Tech Mono\',monospace;--sans:\'Rajdhani\',sans-serif;\n}\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\nhtml{font-size:16px;scroll-behavior:smooth}\nbody{background:var(--bg);color:var(--text);font-family:var(--sans);min-height:100vh;overflow-x:hidden;font-size:1rem}\nbody::before{content:\'\';position:fixed;inset:0;\n  background-image:linear-gradient(rgba(168,216,240,.022) 1px,transparent 1px),\n  linear-gradient(90deg,rgba(168,216,240,.022) 1px,transparent 1px);\n  background-size:44px 44px;pointer-events:none;z-index:0}\nbody::after{content:\'\';position:fixed;inset:0;\n  background:repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,.05) 3px,rgba(0,0,0,.05) 4px);\n  pointer-events:none;z-index:9998}\n\n/* ── SIDEBAR NAV ── */\n#sidebar{\n  position:fixed;left:0;top:0;bottom:0;width:200px;\n  background:rgba(13,17,23,.97);border-right:1px solid var(--border);\n  display:flex;flex-direction:column;z-index:1000;\n  backdrop-filter:blur(12px);\n}\n.sb-logo{padding:18px 16px 14px;border-bottom:1px solid var(--border)}\n.sb-logo-text{font-family:var(--mono);font-size:1.1rem;color:var(--accent);\n  letter-spacing:4px;text-shadow:0 0 14px rgba(168,216,240,.45)}\n.sb-logo-text span{color:var(--green)}\n.sb-logo-sub{font-family:var(--mono);font-size:.72rem;color:var(--muted);\n  letter-spacing:2px;margin-top:3px}\n.sb-status{display:flex;align-items:center;gap:6px;padding:10px 16px;\n  border-bottom:1px solid var(--border);font-family:var(--mono);font-size:.75rem;color:var(--green)}\n.sb-dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:pulse 1.5s infinite}\n@keyframes pulse{0%,100%{opacity:1;box-shadow:0 0 6px var(--green)}50%{opacity:.3;box-shadow:none}}\n.sb-nav{flex:1;padding:10px 0;overflow-y:auto}\n.sb-nav a{\n  display:flex;align-items:center;gap:10px;\n  padding:10px 16px;text-decoration:none;\n  font-family:var(--sans);font-size:.92rem;font-weight:600;\n  letter-spacing:1.5px;text-transform:uppercase;\n  color:var(--muted);border-left:2px solid transparent;\n  transition:all .2s;\n}\n.sb-nav a:hover{color:var(--text);background:rgba(168,216,240,.04);border-left-color:var(--muted)}\n.sb-nav a.active{color:var(--accent);background:rgba(168,216,240,.06);border-left-color:var(--accent)}\n.sb-nav a .nav-icon{font-size:1rem;width:18px;text-align:center}\n.sb-nav .nav-badge{margin-left:auto;font-family:var(--mono);font-size:.68rem;\n  padding:1px 5px;border:1px solid rgba(168,216,240,.2);color:var(--muted)}\n.sb-nav a.active .nav-badge{border-color:rgba(168,216,240,.4);color:var(--accent)}\n.sb-footer{padding:12px 16px;border-top:1px solid var(--border)}\n.sb-clock{font-family:var(--mono);font-size:.78rem;color:var(--muted)}\n.sb-cmd{font-family:var(--mono);font-size:.72rem;color:rgba(58,106,132,.5);\n  margin-top:6px;line-height:1.6}\n.sb-cmd span{color:var(--accent)}\n\n/* ── PAGE WRAPPER ── */\n#page{margin-left:200px;position:relative;z-index:1;padding:16px;min-height:100vh}\n\n/* ── PAGE HEADER ── */\n.page-hdr{margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;justify-content:space-between}\n.page-title{font-family:var(--mono);font-size:1.2rem;color:var(--accent);letter-spacing:3px;text-transform:uppercase}\n.page-sub{font-size:.85rem;color:var(--muted);margin-top:3px}\n.page-meta{font-family:var(--mono);font-size:.75rem;color:var(--muted)}\n\n/* ── STAT CARDS ── */\n.stat-row{display:grid;gap:10px;margin-bottom:16px}\n.stat-card{background:var(--panel);border:1px solid var(--border);padding:14px 18px;position:relative;overflow:hidden}\n.stat-card::before{content:\'\';position:absolute;top:0;left:0;width:100%;height:2px;\n  background:linear-gradient(90deg,var(--ca,var(--accent)),var(--cb,var(--green)))}\n.stat-label{font-family:var(--mono);font-size:.72rem;letter-spacing:2px;color:var(--muted);\n  text-transform:uppercase;margin-bottom:6px}\n.stat-val{font-family:var(--mono);font-size:2.2rem;color:#fff;line-height:1;transition:all .3s}\n.stat-val.bump{color:var(--accent);text-shadow:0 0 18px rgba(168,216,240,.5)}\n.stat-sub{font-size:.75rem;color:var(--muted);margin-top:3px}\n\n/* ── PANEL ── */\n.panel{background:var(--panel);border:1px solid var(--border);display:flex;flex-direction:column;overflow:hidden}\n.panel-hdr{padding:9px 13px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;gap:8px;flex-shrink:0}\n.panel-title{font-family:var(--mono);font-size:.78rem;letter-spacing:2px;text-transform:uppercase;color:var(--accent)}\n.panel-badge{margin-left:auto;font-family:var(--mono);font-size:.72rem;\n  padding:2px 8px;border:1px solid rgba(168,216,240,.22);color:var(--muted)}\n.panel-body{flex:1;overflow:hidden;padding:12px}\n.panel-scroll{overflow-y:auto}\n.panel-nopad{padding:0}\n\n/* ── RISK BADGES ── */\n.risk{font-size:.72rem;padding:1px 5px;border-radius:2px;text-transform:uppercase;font-weight:700;letter-spacing:1px}\n.risk-critical{background:rgba(255,107,138,.14);color:var(--red);border:1px solid rgba(255,107,138,.3)}\n.risk-high{background:rgba(255,159,67,.1);color:var(--orange);border:1px solid rgba(255,159,67,.3)}\n.risk-medium{background:rgba(254,202,87,.08);color:#feca57;border:1px solid rgba(254,202,87,.3)}\n.risk-low{background:rgba(168,216,240,.07);color:var(--muted);border:1px solid rgba(168,216,240,.2)}\n\n/* ── BADGE STATUS ── */\n.badge{font-size:.72rem;padding:1px 6px;border-radius:2px;font-family:var(--sans);font-weight:700;letter-spacing:1px;text-transform:uppercase;white-space:nowrap}\n.badge-honey{background:rgba(127,239,212,.12);color:var(--green);border:1px solid rgba(127,239,212,.28)}\n.badge-threat{background:rgba(255,107,138,.1);color:var(--red);border:1px solid rgba(255,107,138,.26)}\n.badge-ok{background:rgba(168,216,240,.06);color:var(--muted);border:1px solid rgba(168,216,240,.15)}\n\n/* ── TOAST ── */\n#toast-wrap{position:fixed;bottom:16px;right:16px;z-index:9999;display:flex;flex-direction:column;gap:6px;pointer-events:none}\n.toast{background:var(--panel);border:1px solid var(--green);padding:8px 14px;\n  font-family:var(--mono);font-size:.78rem;color:var(--green);\n  box-shadow:0 0 16px rgba(127,239,212,.14);max-width:300px;\n  animation:tIn .3s ease,tOut .3s ease 3.7s forwards}\n.toast.danger{border-color:var(--red);color:var(--red);box-shadow:0 0 16px rgba(255,107,138,.14)}\n@keyframes tIn{from{opacity:0;transform:translateX(14px)}to{opacity:1;transform:translateX(0)}}\n@keyframes tOut{from{opacity:1}to{opacity:0}}\n\n/* ── SCROLLBARS ── */\n::-webkit-scrollbar{width:3px;height:3px}\n::-webkit-scrollbar-track{background:var(--bg)}\n::-webkit-scrollbar-thumb{background:var(--border);border-radius:2px}\n</style>\n\n<style>\n/* ── PORT GRID ── */\n#port-grid{{\n  display:grid;\n  grid-template-columns:repeat(auto-fill,minmax(52px,1fr));\n  gap:3px;padding:10px;\n}}\n.port-cell{{\n  aspect-ratio:1;display:flex;flex-direction:column;align-items:center;\n  justify-content:center;font-family:var(--mono);font-size:.82rem;\n  background:var(--panel2);border:1px solid rgba(42,74,100,.5);\n  cursor:pointer;transition:all .18s;position:relative;\n  user-select:none;\n}}\n.port-cell:hover{{border-color:var(--accent);background:rgba(168,216,240,.06);z-index:2}}\n.port-cell.hit-low{{border-color:rgba(168,216,240,.4);background:rgba(168,216,240,.05)}}\n.port-cell.hit-medium{{border-color:rgba(254,202,87,.5);background:rgba(254,202,87,.05)}}\n.port-cell.hit-high{{border-color:rgba(255,159,67,.6);background:rgba(255,159,67,.06)}}\n.port-cell.hit-critical{{border-color:rgba(255,107,138,.7);background:rgba(255,107,138,.07);\n  box-shadow:0 0 8px rgba(255,107,138,.15)}}\n.port-cell.firing{{animation:cellFire .6s ease}}\n@keyframes cellFire{{0%,100%{{}}50%{{background:rgba(127,239,212,.15);border-color:var(--green)}}}}\n.port-num{{color:var(--text);font-size:.75rem;font-weight:bold}}\n.port-hits{{color:var(--green);font-size:.8rem;margin-top:1px}}\n.port-svc{{color:var(--muted);font-size:.76rem;margin-top:1px;white-space:nowrap;\n  overflow:hidden;text-overflow:ellipsis;max-width:90%;text-align:center}}\n.port-cell.known .port-num{{color:var(--accent)}}\n\n/* ── PORT TOOLTIP ── */\n#port-tooltip{{\n  position:fixed;pointer-events:none;z-index:9000;\n  background:var(--bg2);border:1px solid var(--border);\n  padding:10px 14px;font-family:var(--mono);font-size:.82rem;\n  min-width:200px;box-shadow:0 4px 20px rgba(0,0,0,.4);\n  display:none;\n}}\n#port-tooltip .tt-port{{color:var(--accent);font-size:.9rem;margin-bottom:4px}}\n#port-tooltip .tt-row{{display:flex;justify-content:space-between;gap:16px;\n  color:var(--muted);font-size:.76rem;margin-top:3px}}\n#port-tooltip .tt-val{{color:var(--text)}}\n\n/* ── HOT PORTS ── */\n.hp-row{{display:grid;grid-template-columns:48px 1fr 60px 70px 70px;gap:8px;\n  padding:7px 12px;border-bottom:1px solid rgba(42,74,100,.4);\n  font-family:var(--mono);font-size:.82rem;align-items:center;transition:background .15s}}\n.hp-row:hover{{background:rgba(168,216,240,.04)}}\n.hp-row-hdr{{color:var(--muted);font-size:.72rem;letter-spacing:1.5px;text-transform:uppercase;\n  background:var(--bg2);border-bottom:1px solid var(--border)}}\n</style>\n</head>\n<body>\n\n<div id="sidebar">\n  <div class="sb-logo">\n    <div class="sb-logo-text">COG<span>NI</span>SEC</div>\n    <div class="sb-logo-sub">DECEPTION ENGINE</div>\n  </div>\n  <div class="sb-status"><div class="sb-dot"></div>SYSTEM ACTIVE</div>\n  <nav class="sb-nav"><a href="/"><span class="nav-icon">🏠</span>Overview<span class="nav-badge" id="s-threats-nav">—</span></a><a href="/traffic"><span class="nav-icon">📡</span>Live Traffic<span class="nav-badge" id="s-feed-nav">—</span></a><a href="/honeypots" class="active"><span class="nav-icon">🍯</span>Honeypots<span class="nav-badge" id="s-hp-nav">—</span></a><a href="/attackers"><span class="nav-icon">👾</span>Attackers<span class="nav-badge" id="s-atk-nav">—</span></a></nav>\n  <div class="sb-footer">\n    <div class="sb-clock" id="sb-clock">--:--:--</div>\n    <div class="sb-cmd">$ <span>python attacker.py</span></div>\n  </div>\n</div>\n\n<div id="page">\n\n  <div class="page-hdr">\n    <div>\n      <div class="page-title">// Honeypot Grid</div>\n      <div class="page-sub">All 1024 registered ports — click any cell to inspect</div>\n    </div>\n    <div style="display:flex;align-items:center;gap:10px">\n      <div style="font-family:var(--mono);font-size:.76rem;color:var(--muted)">\n        <span style="color:var(--red)">■</span> critical &nbsp;\n        <span style="color:var(--orange)">■</span> high &nbsp;\n        <span style="color:#feca57">■</span> medium &nbsp;\n        <span style="color:var(--accent)">■</span> low/no hit\n      </div>\n      <div class="panel-badge" id="hp-hit-count">0 ports hit</div>\n    </div>\n  </div>\n\n  <!-- STAT ROW -->\n  <div class="stat-row" style="grid-template-columns:repeat(4,1fr);margin-bottom:14px">\n    <div class="stat-card" style="--ca:#7fefd4;--cb:#a8d8f0">\n      <div class="stat-label">// ports armed</div>\n      <div class="stat-val" id="s-armed">1024</div></div>\n    <div class="stat-card" style="--ca:#ff6b8a;--cb:#ff9f43">\n      <div class="stat-label">// ports hit</div>\n      <div class="stat-val" id="s-hit">0</div></div>\n    <div class="stat-card" style="--ca:#feca57;--cb:#ff9f43">\n      <div class="stat-label">// total connections</div>\n      <div class="stat-val" id="s-conns">0</div></div>\n    <div class="stat-card" style="--ca:#b8d4f0;--cb:#fd79a8">\n      <div class="stat-label">// bytes captured</div>\n      <div class="stat-val" id="s-bytes">0</div></div>\n  </div>\n\n  <div style="display:grid;grid-template-columns:1fr 300px;gap:12px">\n\n    <!-- PORT GRID -->\n    <div class="panel" style="overflow:hidden">\n      <div class="panel-hdr">\n        <div class="panel-title">🗺 Port Coverage Map (1–1024)</div>\n        <div class="panel-badge" id="grid-status">ARMED</div>\n      </div>\n      <div class="panel-body panel-nopad" style="overflow-y:auto;max-height:calc(100vh - 240px)">\n        <div id="port-grid"></div>\n      </div>\n    </div>\n\n    <!-- RIGHT COLUMN -->\n    <div style="display:flex;flex-direction:column;gap:12px">\n\n      <!-- Hot Ports -->\n      <div class="panel" style="flex:1">\n        <div class="panel-hdr">\n          <div class="panel-title">🔥 Most Attacked Ports</div>\n          <div class="panel-badge" id="hot-count">0</div>\n        </div>\n        <div class="panel-body panel-nopad" style="overflow-y:auto;max-height:260px">\n          <div class="hp-row hp-row-hdr">\n            <span>PORT</span><span>SERVICE</span><span>HITS</span><span>RISK</span><span>CATEGORY</span>\n          </div>\n          <div id="hot-ports-list"></div>\n        </div>\n      </div>\n\n      <!-- Category chart -->\n      <div class="panel" style="flex-shrink:0">\n        <div class="panel-hdr"><div class="panel-title">🗂 Category Breakdown</div></div>\n        <div class="panel-body" style="height:200px;padding:10px">\n          <canvas id="catChart"></canvas>\n        </div>\n      </div>\n\n    </div>\n  </div>\n\n</div>\n\n<!-- PORT TOOLTIP -->\n<div id="port-tooltip">\n  <div class="tt-port" id="tt-port">—</div>\n  <div class="tt-row"><span>Service</span><span class="tt-val" id="tt-svc">—</span></div>\n  <div class="tt-row"><span>Category</span><span class="tt-val" id="tt-cat">—</span></div>\n  <div class="tt-row"><span>Risk</span><span class="tt-val" id="tt-risk">—</span></div>\n  <div class="tt-row"><span>Banner</span><span class="tt-val" id="tt-banner" style="max-width:160px;text-align:right;word-break:break-all">—</span></div>\n  <div class="tt-row"><span>Connections</span><span class="tt-val" id="tt-conns" style="color:var(--green)">0</span></div>\n  <div class="tt-row"><span>Last Hit</span><span class="tt-val" id="tt-last">—</span></div>\n</div>\n\n\n<div id="toast-wrap"></div>\n<script>\n// ── CLOCK ──\nfunction _clockTick(){\n  const el=document.getElementById(\'sb-clock\');\n  if(el) el.textContent=new Date().toTimeString().slice(0,8);\n}\nsetInterval(_clockTick,500); _clockTick();\n\n// ── STAT BUMP ──\nfunction bump(id,val){\n  const el=document.getElementById(id);\n  if(!el)return;\n  el.textContent=val;\n  el.classList.add(\'bump\');\n  setTimeout(()=>el.classList.remove(\'bump\'),500);\n}\n\n// ── TOAST ──\nfunction toast(msg,danger=false){\n  const c=document.getElementById(\'toast-wrap\');\n  const d=document.createElement(\'div\');\n  d.className=\'toast\'+(danger?\' danger\':\'\');\n  d.textContent=msg;c.appendChild(d);\n  setTimeout(()=>d.remove(),4200);\n}\n\n// ── TECH COLORS ──\nconst TECH_COLORS={\n  port_scan:\'#a8d8f0\',stealth_scan:\'#b8d4f0\',brute_force:\'#ff9f43\',\n  credential_stuff:\'#fd79a8\',vuln_scan:\'#feca57\',exploit_known:\'#ff6b6b\',\n  syn_flood:\'#ff0000\',lateral_move:\'#ff6b8a\',zero_day:\'#fd79a8\',\n  data_exfil:\'#e17055\',unknown:\'#888\'\n};\nconst RISK_COLORS={critical:\'#ff6b8a\',high:\'#ff9f43\',medium:\'#feca57\',low:\'#a8d8f0\'};\n\n// ── ATTACK SUMMARIES ──\nconst ATTACK_SUMMARIES={\n  port_scan:\'Systematically probing ports to map open services. Attacker is in reconnaissance phase building a target profile.\',\n  stealth_scan:\'Low-rate randomised port sweep designed to evade rate-based detection. Indicates a patient, skilled actor.\',\n  brute_force:\'Repeated authentication attempts with credential lists. Attacker is trying to gain direct access.\',\n  credential_stuff:\'Using leaked credential databases across multiple services simultaneously.\',\n  vuln_scan:\'Automated probing for known CVEs and misconfigurations in web-facing services.\',\n  exploit_known:\'Attempting to exploit a known vulnerability. Attacker has identified a specific attack surface.\',\n  syn_flood:\'High-rate SYN packet flood — denial-of-service attempt targeting connection tables.\',\n  lateral_move:\'Post-compromise movement across the network. Attacker already has a foothold.\',\n  zero_day:\'Anomalous payload patterns inconsistent with any known attack signature. Possible novel exploit.\',\n  data_exfil:\'Encoding data in covert channels (DNS/HTTPS tunnelling) to exfiltrate captured information.\',\n  unknown:\'Unclassified traffic pattern with anomalous characteristics.\'\n};\n</script>\n\n<script>\nlet portData={}, catChart;\nconst KNOWN=[22,23,25,53,67,68,69,79,80,81,88,102,110,111,115,119,123,135,137,138,139,\n  143,161,162,179,194,389,443,445,465,502,512,513,514,543,544,587,591,631,636,\n  873,989,990,993,995,1080,1433,1521,3128,3306,3389,5060,5061,5432,5672,5900,5901,6379,6667,8008,8080,8443,8888,9090,9200,9300];\n\nfunction initGrid(){\n  const grid=document.getElementById(\'port-grid\');\n  grid.innerHTML=\'\';\n  for(let p=1;p<=1024;p++){\n    const cell=document.createElement(\'div\');\n    cell.className=\'port-cell\'+(KNOWN.includes(p)?\' known\':\'\');\n    cell.id=\'pc-\'+p;\n    cell.dataset.port=p;\n    cell.innerHTML=`<div class="port-num">${p}</div><div class="port-svc" id="ps-${p}"></div><div class="port-hits" id="ph-${p}"></div>`;\n    cell.addEventListener(\'mouseenter\',showTooltip);\n    cell.addEventListener(\'mouseleave\',hideTooltip);\n    cell.addEventListener(\'mousemove\',moveTooltip);\n    grid.appendChild(cell);\n  }\n}\n\nfunction showTooltip(e){\n  const p=parseInt(e.currentTarget.dataset.port);\n  const hp=portData[p];if(!hp)return;\n  document.getElementById(\'tt-port\').textContent=\':\'+p;\n  document.getElementById(\'tt-svc\').textContent=hp.service||\'—\';\n  document.getElementById(\'tt-cat\').textContent=hp.category||\'—\';\n  document.getElementById(\'tt-risk\').textContent=hp.risk||\'—\';\n  document.getElementById(\'tt-risk\').className=\'tt-val risk risk-\'+(hp.risk||\'low\');\n  document.getElementById(\'tt-banner\').textContent=hp.banner||\'—\';\n  document.getElementById(\'tt-conns\').textContent=hp.connections||0;\n  document.getElementById(\'tt-last\').textContent=hp.last_hit?hp.last_hit.slice(11,19):\'Never\';\n  const tt=document.getElementById(\'port-tooltip\');\n  tt.style.display=\'block\';moveTooltip(e);\n}\nfunction hideTooltip(){document.getElementById(\'port-tooltip\').style.display=\'none\'}\nfunction moveTooltip(e){\n  const tt=document.getElementById(\'port-tooltip\');\n  let x=e.clientX+14,y=e.clientY-10;\n  if(x+220>window.innerWidth)x=e.clientX-224;\n  if(y+160>window.innerHeight)y=e.clientY-164;\n  tt.style.left=x+\'px\';tt.style.top=y+\'px\';\n}\n\nfunction updateGrid(hps){\n  let totalHit=0,totalConns=0,totalBytes=0;\n  Object.entries(hps).forEach(([portStr,hp])=>{\n    const p=parseInt(portStr);\n    portData[p]=hp;\n    const cell=document.getElementById(\'pc-\'+p);\n    if(!cell)return;\n    const hits=hp.connections||0;\n    if(hits>0){\n      totalHit++;totalConns+=hits;totalBytes+=(hp.bytes_captured||0);\n      cell.className=\'port-cell\'+(KNOWN.includes(p)?\' known\':\'\')+ \' hit-\'+(hp.risk||\'low\');\n      document.getElementById(\'ph-\'+p).textContent=hits+\'x\';\n    }\n    const svcEl=document.getElementById(\'ps-\'+p);\n    if(svcEl&&hp.service) svcEl.textContent=hp.service.slice(0,6);\n  });\n  bump(\'s-hit\',totalHit);bump(\'s-conns\',totalConns);\n  bump(\'s-bytes\',totalBytes>1024?(totalBytes/1024).toFixed(1)+\'K\':totalBytes+\'B\');\n  document.getElementById(\'hp-hit-count\').textContent=totalHit+\' ports hit\';\n}\n\nfunction fireCell(port){\n  const cell=document.getElementById(\'pc-\'+port);\n  if(cell){cell.classList.add(\'firing\');setTimeout(()=>cell.classList.remove(\'firing\'),700)}\n}\n\nfunction renderHotPorts(ports){\n  const el=document.getElementById(\'hot-ports-list\');\n  if(!ports||!ports.length){el.innerHTML=\'<div style="padding:16px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.8rem">NO HITS YET</div>\';return}\n  el.innerHTML=\'\';\n  document.getElementById(\'hot-count\').textContent=ports.length;\n  ports.forEach(p=>{\n    const d=document.createElement(\'div\');d.className=\'hp-row\';\n    d.innerHTML=`<span style="color:var(--accent)">:${p.port}</span><span style="color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${p.service}</span><span style="color:var(--green)">${p.hits}</span><span class="risk risk-${p.risk}">${p.risk}</span><span style="color:var(--muted);font-size:.6rem">${p.category||\'—\'}</span>`;\n    el.appendChild(d);\n  });\n}\n\nfunction initCatChart(){\n  catChart=new Chart(document.getElementById(\'catChart\').getContext(\'2d\'),{\n    type:\'bar\',\n    data:{labels:[],datasets:[{data:[],\n      backgroundColor:[\'#ff6b8a\',\'#ff9f43\',\'#feca57\',\'#a8d8f0\',\'#b8d4f0\',\'#7fefd4\',\'#fd79a8\',\'#e17055\',\'#74b9ff\'],\n      borderWidth:0}]},\n    options:{responsive:true,maintainAspectRatio:false,indexAxis:\'y\',\n      plugins:{legend:{display:false}},\n      scales:{x:{ticks:{color:\'#4a7a9b\',font:{size:8}},grid:{color:\'rgba(42,74,100,.3)\'}},\n              y:{ticks:{color:\'#e0f0f8\',font:{family:\'Share Tech Mono\',size:9}},grid:{display:false}}}}\n  });\n}\n\nasync function poll(){\n  try{\n    const d=await fetch(\'/api/state\').then(r=>r.json());\n    updateGrid(d.honeypots);\n    renderHotPorts(d.hot_ports);\n    if(d.category_counts&&Object.keys(d.category_counts).length){\n      catChart.data.labels=Object.keys(d.category_counts);\n      catChart.data.datasets[0].data=Object.values(d.category_counts);\n      catChart.update(\'none\');\n    }\n    const sn=document.getElementById(\'s-hp-nav\');if(sn)sn.textContent=(d.hot_ports||[]).length;\n  }catch(e){}\n}\n\nfunction connectSSE(){\n  const es=new EventSource(\'/api/stream\');\n  es.onmessage=e=>{\n    try{\n      const msg=JSON.parse(e.data);\n      if(msg.kind===\'redirect\') fireCell(msg.data.to_port);\n    }catch(_){}\n  };\n  es.onerror=()=>{setTimeout(connectSSE,3000);es.close()};\n}\n\nwindow.addEventListener(\'DOMContentLoaded\',()=>{\n  initGrid();initCatChart();connectSSE();poll();setInterval(poll,3000);\n});\n</script>\n</body></html>', 'attackers': '<!DOCTYPE html>\n<html lang="en">\n<head>\n<title>COGNISEC — Attacker Intelligence</title>\n\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<link href="https://fonts.googleapis.com/css2?family=Share+Tech+Mono&family=Rajdhani:wght@400;600;700&family=Exo+2:wght@300;700;900&display=swap" rel="stylesheet">\n<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>\n<style>\n:root{\n  --bg:#0d1117;--bg2:#111b24;--panel:#152030;--panel2:#182535;\n  --border:#2a4a64;--accent:#a8d8f0;--green:#7fefd4;--orange:#ff9f43;\n  --red:#ff6b8a;--purple:#b8d4f0;--muted:#4a7a9b;--text:#e0f0f8;\n  --mono:\'Share Tech Mono\',monospace;--sans:\'Rajdhani\',sans-serif;\n}\n*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}\nhtml{font-size:16px;scroll-behavior:smooth}\nbody{background:var(--bg);color:var(--text);font-family:var(--sans);min-height:100vh;overflow-x:hidden;font-size:1rem}\nbody::before{content:\'\';position:fixed;inset:0;\n  background-image:linear-gradient(rgba(168,216,240,.022) 1px,transparent 1px),\n  linear-gradient(90deg,rgba(168,216,240,.022) 1px,transparent 1px);\n  background-size:44px 44px;pointer-events:none;z-index:0}\nbody::after{content:\'\';position:fixed;inset:0;\n  background:repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,0,0,.05) 3px,rgba(0,0,0,.05) 4px);\n  pointer-events:none;z-index:9998}\n\n/* ── SIDEBAR NAV ── */\n#sidebar{\n  position:fixed;left:0;top:0;bottom:0;width:200px;\n  background:rgba(13,17,23,.97);border-right:1px solid var(--border);\n  display:flex;flex-direction:column;z-index:1000;\n  backdrop-filter:blur(12px);\n}\n.sb-logo{padding:18px 16px 14px;border-bottom:1px solid var(--border)}\n.sb-logo-text{font-family:var(--mono);font-size:1.1rem;color:var(--accent);\n  letter-spacing:4px;text-shadow:0 0 14px rgba(168,216,240,.45)}\n.sb-logo-text span{color:var(--green)}\n.sb-logo-sub{font-family:var(--mono);font-size:.72rem;color:var(--muted);\n  letter-spacing:2px;margin-top:3px}\n.sb-status{display:flex;align-items:center;gap:6px;padding:10px 16px;\n  border-bottom:1px solid var(--border);font-family:var(--mono);font-size:.75rem;color:var(--green)}\n.sb-dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:pulse 1.5s infinite}\n@keyframes pulse{0%,100%{opacity:1;box-shadow:0 0 6px var(--green)}50%{opacity:.3;box-shadow:none}}\n.sb-nav{flex:1;padding:10px 0;overflow-y:auto}\n.sb-nav a{\n  display:flex;align-items:center;gap:10px;\n  padding:10px 16px;text-decoration:none;\n  font-family:var(--sans);font-size:.92rem;font-weight:600;\n  letter-spacing:1.5px;text-transform:uppercase;\n  color:var(--muted);border-left:2px solid transparent;\n  transition:all .2s;\n}\n.sb-nav a:hover{color:var(--text);background:rgba(168,216,240,.04);border-left-color:var(--muted)}\n.sb-nav a.active{color:var(--accent);background:rgba(168,216,240,.06);border-left-color:var(--accent)}\n.sb-nav a .nav-icon{font-size:1rem;width:18px;text-align:center}\n.sb-nav .nav-badge{margin-left:auto;font-family:var(--mono);font-size:.68rem;\n  padding:1px 5px;border:1px solid rgba(168,216,240,.2);color:var(--muted)}\n.sb-nav a.active .nav-badge{border-color:rgba(168,216,240,.4);color:var(--accent)}\n.sb-footer{padding:12px 16px;border-top:1px solid var(--border)}\n.sb-clock{font-family:var(--mono);font-size:.78rem;color:var(--muted)}\n.sb-cmd{font-family:var(--mono);font-size:.72rem;color:rgba(58,106,132,.5);\n  margin-top:6px;line-height:1.6}\n.sb-cmd span{color:var(--accent)}\n\n/* ── PAGE WRAPPER ── */\n#page{margin-left:200px;position:relative;z-index:1;padding:16px;min-height:100vh}\n\n/* ── PAGE HEADER ── */\n.page-hdr{margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;justify-content:space-between}\n.page-title{font-family:var(--mono);font-size:1.2rem;color:var(--accent);letter-spacing:3px;text-transform:uppercase}\n.page-sub{font-size:.85rem;color:var(--muted);margin-top:3px}\n.page-meta{font-family:var(--mono);font-size:.75rem;color:var(--muted)}\n\n/* ── STAT CARDS ── */\n.stat-row{display:grid;gap:10px;margin-bottom:16px}\n.stat-card{background:var(--panel);border:1px solid var(--border);padding:14px 18px;position:relative;overflow:hidden}\n.stat-card::before{content:\'\';position:absolute;top:0;left:0;width:100%;height:2px;\n  background:linear-gradient(90deg,var(--ca,var(--accent)),var(--cb,var(--green)))}\n.stat-label{font-family:var(--mono);font-size:.72rem;letter-spacing:2px;color:var(--muted);\n  text-transform:uppercase;margin-bottom:6px}\n.stat-val{font-family:var(--mono);font-size:2.2rem;color:#fff;line-height:1;transition:all .3s}\n.stat-val.bump{color:var(--accent);text-shadow:0 0 18px rgba(168,216,240,.5)}\n.stat-sub{font-size:.75rem;color:var(--muted);margin-top:3px}\n\n/* ── PANEL ── */\n.panel{background:var(--panel);border:1px solid var(--border);display:flex;flex-direction:column;overflow:hidden}\n.panel-hdr{padding:9px 13px;border-bottom:1px solid var(--border);\n  display:flex;align-items:center;gap:8px;flex-shrink:0}\n.panel-title{font-family:var(--mono);font-size:.78rem;letter-spacing:2px;text-transform:uppercase;color:var(--accent)}\n.panel-badge{margin-left:auto;font-family:var(--mono);font-size:.72rem;\n  padding:2px 8px;border:1px solid rgba(168,216,240,.22);color:var(--muted)}\n.panel-body{flex:1;overflow:hidden;padding:12px}\n.panel-scroll{overflow-y:auto}\n.panel-nopad{padding:0}\n\n/* ── RISK BADGES ── */\n.risk{font-size:.72rem;padding:1px 5px;border-radius:2px;text-transform:uppercase;font-weight:700;letter-spacing:1px}\n.risk-critical{background:rgba(255,107,138,.14);color:var(--red);border:1px solid rgba(255,107,138,.3)}\n.risk-high{background:rgba(255,159,67,.1);color:var(--orange);border:1px solid rgba(255,159,67,.3)}\n.risk-medium{background:rgba(254,202,87,.08);color:#feca57;border:1px solid rgba(254,202,87,.3)}\n.risk-low{background:rgba(168,216,240,.07);color:var(--muted);border:1px solid rgba(168,216,240,.2)}\n\n/* ── BADGE STATUS ── */\n.badge{font-size:.72rem;padding:1px 6px;border-radius:2px;font-family:var(--sans);font-weight:700;letter-spacing:1px;text-transform:uppercase;white-space:nowrap}\n.badge-honey{background:rgba(127,239,212,.12);color:var(--green);border:1px solid rgba(127,239,212,.28)}\n.badge-threat{background:rgba(255,107,138,.1);color:var(--red);border:1px solid rgba(255,107,138,.26)}\n.badge-ok{background:rgba(168,216,240,.06);color:var(--muted);border:1px solid rgba(168,216,240,.15)}\n\n/* ── TOAST ── */\n#toast-wrap{position:fixed;bottom:16px;right:16px;z-index:9999;display:flex;flex-direction:column;gap:6px;pointer-events:none}\n.toast{background:var(--panel);border:1px solid var(--green);padding:8px 14px;\n  font-family:var(--mono);font-size:.78rem;color:var(--green);\n  box-shadow:0 0 16px rgba(127,239,212,.14);max-width:300px;\n  animation:tIn .3s ease,tOut .3s ease 3.7s forwards}\n.toast.danger{border-color:var(--red);color:var(--red);box-shadow:0 0 16px rgba(255,107,138,.14)}\n@keyframes tIn{from{opacity:0;transform:translateX(14px)}to{opacity:1;transform:translateX(0)}}\n@keyframes tOut{from{opacity:1}to{opacity:0}}\n\n/* ── SCROLLBARS ── */\n::-webkit-scrollbar{width:3px;height:3px}\n::-webkit-scrollbar-track{background:var(--bg)}\n::-webkit-scrollbar-thumb{background:var(--border);border-radius:2px}\n</style>\n\n<style>\n/* ── ATTACKER CARD ── */\n.atk-card{{\n  background:var(--panel2);border:1px solid var(--border);\n  padding:14px 16px;position:relative;overflow:hidden;\n  transition:border-color .2s;animation:slideUp .3s ease;\n}}\n.atk-card:hover{{border-color:rgba(255,107,138,.4)}}\n.atk-card::before{{content:\'\';position:absolute;top:0;left:0;width:3px;height:100%;background:var(--red)}}\n@keyframes slideUp{{from{{opacity:0;transform:translateY(10px)}}to{{opacity:1;transform:translateY(0)}}}}\n.atk-ip{{font-family:var(--mono);font-size:1rem;color:var(--accent);margin-bottom:4px}}\n.atk-profile{{font-family:var(--sans);font-size:.85rem;color:var(--muted);margin-bottom:8px}}\n.atk-meta{{display:flex;flex-wrap:wrap;gap:10px}}\n.atk-meta-item{{font-family:var(--mono);font-size:.78rem;color:var(--muted)}}\n.atk-meta-item span{{color:var(--text)}}\n.skill-pips{{display:flex;gap:3px;margin-top:6px}}\n.skill-pip{{width:16px;height:6px;border-radius:1px;background:var(--border)}}\n.skill-pip.on{{background:var(--red);box-shadow:0 0 4px rgba(255,107,138,.5)}}\n\n/* ── DECEPTION LOG ── */\n.dl-row{{\n  padding:11px 14px;border-bottom:1px solid var(--border);\n  animation:fadeRow .3s ease;cursor:pointer;transition:background .15s;\n}}\n.dl-row:hover{{background:rgba(168,216,240,.04)}}\n.dl-row.expanded{{background:rgba(168,216,240,.05);border-left:3px solid var(--accent)}}\n@keyframes fadeRow{{from{{opacity:0;background:rgba(127,239,212,.05)}}to{{opacity:1}}}}\n.dl-row-top{{display:flex;align-items:center;gap:8px}}\n.dl-ip{{font-family:var(--mono);font-size:.85rem;color:var(--red);flex:1}}\n.dl-arrow{{color:var(--muted);font-size:.8rem}}\n.dl-hp{{font-family:var(--mono);font-size:.85rem;color:var(--green)}}\n.dl-ts{{font-family:var(--mono);font-size:.72rem;color:var(--muted)}}\n.dl-banner{{font-family:var(--mono);font-size:.75rem;color:var(--muted);margin-top:3px;\n  white-space:nowrap;overflow:hidden;text-overflow:ellipsis}}\n.dl-ports{{font-size:.78rem;color:var(--text);margin-top:3px}}\n.dl-ports em{{font-style:normal;color:var(--red)}}\n.dl-ports .dl-to{{color:var(--green)}}\n.dl-expand{{background:var(--panel);border:1px solid var(--border);padding:12px;margin-top:10px;\n  font-family:var(--mono);font-size:.78rem;line-height:1.9;display:none}}\n.dl-row.expanded .dl-expand{{display:block}}\n\n/* ── IP STATS ── */\n.ip-stat-row{{display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-top:8px}}\n.ip-stat{{background:var(--panel);border:1px solid var(--border);padding:8px 11px}}\n.ip-stat-label{{font-family:var(--mono);font-size:.65rem;color:var(--muted);letter-spacing:1px;text-transform:uppercase}}\n.ip-stat-val{{font-family:var(--mono);font-size:.95rem;color:var(--accent)}}\n</style>\n</head>\n<body>\n\n<div id="sidebar">\n  <div class="sb-logo">\n    <div class="sb-logo-text">COG<span>NI</span>SEC</div>\n    <div class="sb-logo-sub">DECEPTION ENGINE</div>\n  </div>\n  <div class="sb-status"><div class="sb-dot"></div>SYSTEM ACTIVE</div>\n  <nav class="sb-nav"><a href="/"><span class="nav-icon">🏠</span>Overview<span class="nav-badge" id="s-threats-nav">—</span></a><a href="/traffic"><span class="nav-icon">📡</span>Live Traffic<span class="nav-badge" id="s-feed-nav">—</span></a><a href="/honeypots"><span class="nav-icon">🍯</span>Honeypots<span class="nav-badge" id="s-hp-nav">—</span></a><a href="/attackers" class="active"><span class="nav-icon">👾</span>Attackers<span class="nav-badge" id="s-atk-nav">—</span></a></nav>\n  <div class="sb-footer">\n    <div class="sb-clock" id="sb-clock">--:--:--</div>\n    <div class="sb-cmd">$ <span>python attacker.py</span></div>\n  </div>\n</div>\n\n<div id="page">\n\n  <div class="page-hdr">\n    <div>\n      <div class="page-title">// Attacker Intelligence</div>\n      <div class="page-sub">Active sessions, trapped attackers, and behavioral intelligence</div>\n    </div>\n    <div style="display:flex;align-items:center;gap:10px">\n      <div style="font-family:var(--mono);font-size:.75rem;color:var(--muted)" id="persist-badge">PERSISTED UNTIL SERVER STOP</div>\n    </div>\n  </div>\n\n  <!-- STAT ROW -->\n  <div class="stat-row" style="grid-template-columns:repeat(4,1fr);margin-bottom:14px">\n    <div class="stat-card" style="--ca:#ff6b8a;--cb:#ff9f43">\n      <div class="stat-label">// active sessions</div>\n      <div class="stat-val" id="s-active">0</div></div>\n    <div class="stat-card" style="--ca:#7fefd4;--cb:#a8d8f0">\n      <div class="stat-label">// total trapped</div>\n      <div class="stat-val" id="s-trapped">0</div></div>\n    <div class="stat-card" style="--ca:#b8d4f0;--cb:#fd79a8">\n      <div class="stat-label">// unique IPs seen</div>\n      <div class="stat-val" id="s-unique">0</div></div>\n    <div class="stat-card" style="--ca:#feca57;--cb:#ff9f43">\n      <div class="stat-label">// threats detected</div>\n      <div class="stat-val" id="s-threats">0</div></div>\n  </div>\n\n  <div style="display:grid;grid-template-columns:340px 1fr;gap:12px">\n\n    <!-- Active Attackers -->\n    <div style="display:flex;flex-direction:column;gap:12px">\n      <div class="panel">\n        <div class="panel-hdr">\n          <div class="panel-title">👾 Active Sessions</div>\n          <div class="panel-badge" id="atk-count">0 live</div>\n        </div>\n        <div class="panel-body panel-nopad panel-scroll" id="atk-cards" style="max-height:280px">\n          <div id="no-sessions-msg" style="padding:24px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.78rem;line-height:2">\n            NO ACTIVE SESSIONS<br>\n            <span style="font-size:.7rem">Run: python attacker.py</span>\n          </div>\n        </div>\n      </div>\n\n      <!-- Per-IP breakdown -->\n      <div class="panel" style="flex:1">\n        <div class="panel-hdr">\n          <div class="panel-title">🔍 Per-IP Stats</div>\n          <div class="panel-badge" id="ip-count">0 IPs</div>\n        </div>\n        <div class="panel-body panel-nopad panel-scroll" id="ip-breakdown" style="max-height:330px">\n          <div style="padding:20px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.78rem">\n            NO DATA YET\n          </div>\n        </div>\n      </div>\n    </div>\n\n    <!-- Deception Log -->\n    <div class="panel">\n      <div class="panel-hdr">\n        <div class="panel-title">🎯 Deception Log</div>\n        <div style="display:flex;align-items:center;gap:10px;margin-left:auto">\n          <div style="font-family:var(--mono);font-size:.72rem;color:var(--muted)">Click to expand</div>\n          <div class="panel-badge" id="dl-count">0 trapped</div>\n        </div>\n      </div>\n      <div class="panel-body panel-nopad panel-scroll" id="deception-log" style="max-height:calc(100vh - 280px)">\n        <div id="dl-empty" style="padding:32px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.78rem;line-height:2">\n          AWAITING TRAPPED ATTACKERS<br>\n          <span style="font-size:.7rem">Deception events will appear here</span>\n        </div>\n      </div>\n    </div>\n\n  </div>\n</div>\n\n<div id="toast-wrap"></div>\n<script>\n// ── CLOCK ──\nfunction _clockTick(){\n  const el=document.getElementById(\'sb-clock\');\n  if(el) el.textContent=new Date().toTimeString().slice(0,8);\n}\nsetInterval(_clockTick,500); _clockTick();\n\n// ── STAT BUMP ──\nfunction bump(id,val){\n  const el=document.getElementById(id);\n  if(!el)return;\n  el.textContent=val;\n  el.classList.add(\'bump\');\n  setTimeout(()=>el.classList.remove(\'bump\'),500);\n}\n\n// ── TOAST ──\nfunction toast(msg,danger=false){\n  const c=document.getElementById(\'toast-wrap\');\n  const d=document.createElement(\'div\');\n  d.className=\'toast\'+(danger?\' danger\':\'\');\n  d.textContent=msg;c.appendChild(d);\n  setTimeout(()=>d.remove(),4200);\n}\n\n// ── TECH COLORS ──\nconst TECH_COLORS={\n  port_scan:\'#a8d8f0\',stealth_scan:\'#b8d4f0\',brute_force:\'#ff9f43\',\n  credential_stuff:\'#fd79a8\',vuln_scan:\'#feca57\',exploit_known:\'#ff6b6b\',\n  syn_flood:\'#ff0000\',lateral_move:\'#ff6b8a\',zero_day:\'#fd79a8\',\n  data_exfil:\'#e17055\',unknown:\'#888\'\n};\nconst RISK_COLORS={critical:\'#ff6b8a\',high:\'#ff9f43\',medium:\'#feca57\',low:\'#a8d8f0\'};\n\n// ── ATTACK SUMMARIES ──\nconst ATTACK_SUMMARIES={\n  port_scan:\'Systematically probing ports to map open services. Attacker is in reconnaissance phase building a target profile.\',\n  stealth_scan:\'Low-rate randomised port sweep designed to evade rate-based detection. Indicates a patient, skilled actor.\',\n  brute_force:\'Repeated authentication attempts with credential lists. Attacker is trying to gain direct access.\',\n  credential_stuff:\'Using leaked credential databases across multiple services simultaneously.\',\n  vuln_scan:\'Automated probing for known CVEs and misconfigurations in web-facing services.\',\n  exploit_known:\'Attempting to exploit a known vulnerability. Attacker has identified a specific attack surface.\',\n  syn_flood:\'High-rate SYN packet flood — denial-of-service attempt targeting connection tables.\',\n  lateral_move:\'Post-compromise movement across the network. Attacker already has a foothold.\',\n  zero_day:\'Anomalous payload patterns inconsistent with any known attack signature. Possible novel exploit.\',\n  data_exfil:\'Encoding data in covert channels (DNS/HTTPS tunnelling) to exfiltrate captured information.\',\n  unknown:\'Unclassified traffic pattern with anomalous characteristics.\'\n};\n</script>\n\n<script>\n// ── All state lives in ipStats; the deception log DOM is rebuilt from server history\nlet ipStats = {};\nlet renderedLogIds = new Set();\n\n// ── ATTACKER CARDS ──\nfunction renderAttackers(list){\n  const el=document.getElementById(\'atk-cards\');\n  document.getElementById(\'atk-count\').textContent=list.length+\' live\';\n  bump(\'s-active\',list.length);\n  const noMsg=document.getElementById(\'no-sessions-msg\');\n  if(!list.length){\n    if(noMsg) noMsg.style.display=\'\';\n    // Remove any existing cards but keep the no-msg div\n    [...el.children].forEach(c=>{if(c.id!==\'no-sessions-msg\') c.remove()});\n    return;\n  }\n  if(noMsg) noMsg.style.display=\'none\';\n  // Rebuild cards\n  [...el.children].forEach(c=>{if(c.id!==\'no-sessions-msg\') c.remove()});\n  list.forEach(a=>{\n    const card=document.createElement(\'div\');\n    card.className=\'atk-card\';\n    card.style.margin=\'8px\';\n    const pips=[1,2,3,4].map(i=>`<div class="skill-pip${i<=a.skill?\' on\':\'\'}"></div>`).join(\'\');\n    const skillName=[\'\',\'Novice\',\'Intermediate\',\'Advanced\',\'APT/Nation-State\'][a.skill]||\'Unknown\';\n    const meta=ipStats[a.ip]||{packets:0,trapped:0,techniques:new Set()};\n    card.innerHTML=`\n      <div class="atk-ip">${a.ip}</div>\n      <div class="atk-profile">${a.profile} · <span style="color:${a.skill>=4?\'var(--red)\'  :a.skill>=3?\'var(--orange)\':\'var(--muted)\'}">${skillName}</span></div>\n      <div class="skill-pips">${pips}</div>\n      <div class="atk-meta" style="margin-top:10px">\n        <div class="atk-meta-item">Pkts: <span>${meta.packets||0}</span></div>\n        <div class="atk-meta-item">Trapped: <span style="color:var(--green)">${meta.trapped||0}</span></div>\n        <div class="atk-meta-item">Techs: <span>${[...(meta.techniques||[])].join(\', \')||\'—\'}</span></div>\n      </div>`;\n    el.appendChild(card);\n  });\n}\n\n// ── RENDER ONE DECEPTION LOG ENTRY ──\nfunction renderDeceptionEntry(rec){\n  const id=rec.id||(rec.attacker_ip+rec.ts);\n  if(renderedLogIds.has(id)) return;\n  renderedLogIds.add(id);\n\n  const lg=document.getElementById(\'deception-log\');\n  const empty=document.getElementById(\'dl-empty\');\n  if(empty) empty.remove();\n\n  const summary=`The attacker at <strong>${rec.attacker_ip}</strong> probed port ${rec.from_port} (${rec.service||\'unknown\'}) using <strong>${(rec.technique||\'unknown\').replace(/_/g,\' \')}</strong>. COGNISEC silently redirected the connection to a honeypot presenting a fake <strong>${rec.banner||\'service banner\'}</strong>. The attacker believes they are interacting with a real ${rec.category||\'service\'} asset. Risk: <strong style="color:${rec.risk===\'critical\'?\'var(--red)\':\'var(--orange)\'}">${rec.risk||\'unknown\'}</strong>.`;\n\n  const d=document.createElement(\'div\');\n  d.className=\'dl-row\';\n  d.dataset.id=id;\n  d.innerHTML=`\n    <div class="dl-row-top">\n      <span class="dl-ip">${rec.attacker_ip}</span>\n      <span class="dl-arrow">⟶</span>\n      <span class="dl-hp">🍯 ${rec.service||rec.honeypot||rec.to_port}</span>\n      <span class="dl-ts">${rec.ts}</span>\n      <span class="risk risk-${rec.risk||\'low\'}">${rec.risk||\'low\'}</span>\n    </div>\n    <div class="dl-banner">${rec.banner||\'\'}</div>\n    <div class="dl-ports">Port <em>${rec.from_port}</em> → <span class="dl-to">:${rec.to_port}</span>\n      &nbsp;·&nbsp;<span style="color:var(--orange)">${(rec.technique||\'unknown\').replace(/_/g,\' \')}</span>\n    </div>\n    <div class="dl-expand">\n      <div style="color:var(--accent);margin-bottom:8px">// ANALYST SUMMARY</div>\n      <div style="color:var(--text);line-height:1.9">${summary}</div>\n      <div class="ip-stat-row">\n        <div class="ip-stat"><div class="ip-stat-label">Category</div><div class="ip-stat-val">${rec.category||\'—\'}</div></div>\n        <div class="ip-stat"><div class="ip-stat-label">Risk</div><div class="ip-stat-val" style="color:${rec.risk===\'critical\'?\'var(--red)\':\'var(--orange)\'}">${rec.risk||\'—\'}</div></div>\n        <div class="ip-stat"><div class="ip-stat-label">Honeypot Port</div><div class="ip-stat-val">${rec.to_port}</div></div>\n        <div class="ip-stat"><div class="ip-stat-label">Real Port Hit</div><div class="ip-stat-val">${rec.from_port}</div></div>\n      </div>\n    </div>`;\n  d.addEventListener(\'click\',()=>d.classList.toggle(\'expanded\'));\n  lg.prepend(d);\n\n  // Update count badge\n  document.getElementById(\'dl-count\').textContent=renderedLogIds.size+\' trapped\';\n\n  // Update IP stats\n  const ip=rec.attacker_ip;\n  if(!ipStats[ip]) ipStats[ip]={packets:0,trapped:0,techniques:new Set()};\n  ipStats[ip].trapped++;\n  if(rec.technique) ipStats[ip].techniques.add(rec.technique);\n  renderIPBreakdown();\n}\n\n// ── PER-IP BREAKDOWN ──\nfunction renderIPBreakdown(){\n  const el=document.getElementById(\'ip-breakdown\');\n  const entries=Object.entries(ipStats).filter(([,s])=>s.packets>0||s.trapped>0);\n  document.getElementById(\'ip-count\').textContent=entries.length+\' IPs\';\n  bump(\'s-unique\', entries.length);\n  if(!entries.length){el.innerHTML=\'<div style="padding:20px;text-align:center;color:var(--muted);font-family:var(--mono);font-size:.78rem">NO DATA YET</div>\';return}\n  el.innerHTML=\'\';\n  entries.sort((a,b)=>b[1].trapped-a[1].trapped).forEach(([ip,s])=>{\n    const d=document.createElement(\'div\');\n    d.style.cssText=\'padding:10px 14px;border-bottom:1px solid var(--border)\';\n    d.innerHTML=`<div style="font-family:var(--mono);font-size:.85rem;color:var(--accent);margin-bottom:6px">${ip}</div>\n      <div class="ip-stat-row">\n        <div class="ip-stat"><div class="ip-stat-label">Packets</div><div class="ip-stat-val">${s.packets}</div></div>\n        <div class="ip-stat"><div class="ip-stat-label">Trapped</div><div class="ip-stat-val" style="color:var(--green)">${s.trapped}</div></div>\n      </div>\n      <div style="font-family:var(--mono);font-size:.72rem;color:var(--muted);margin-top:7px">Techniques: <span style="color:var(--text)">${[...(s.techniques||[])].join(\', \')||\'—\'}</span></div>`;\n    el.appendChild(d);\n  });\n}\n\n// ── POLL (stats + refresh full deception log from server) ──\nasync function poll(){\n  try{\n    const d=await fetch(\'/api/state\').then(r=>r.json());\n    const s=d.stats;\n    renderAttackers(s.active_attackers);\n    bump(\'s-trapped\', s.attackers_redirected);\n    bump(\'s-threats\', s.threats_detected);\n\n    // Load ALL server-persisted redirections (server keeps up to 500)\n    (d.recent_redirections||[]).forEach(rec=>renderDeceptionEntry(rec));\n\n    const sn=document.getElementById(\'s-atk-nav\');if(sn)sn.textContent=s.active_attackers.length;\n  }catch(e){}\n}\n\n// ── SSE (live new events) ──\nfunction connectSSE(){\n  const es=new EventSource(\'/api/stream\');\n  es.onmessage=e=>{\n    try{\n      const msg=JSON.parse(e.data);\n      if(msg.kind===\'redirect\'){\n        renderDeceptionEntry(msg.data);\n        toast(\'🎯 TRAPPED: \'+msg.data.attacker_ip+\' → \'+msg.data.service);\n      } else if(msg.kind===\'packet\'){\n        const ip=msg.data.src_ip;\n        if(!ipStats[ip]) ipStats[ip]={packets:0,trapped:0,techniques:new Set()};\n        ipStats[ip].packets++;\n        if(msg.data.technique&&msg.data.technique!==\'benign\') ipStats[ip].techniques.add(msg.data.technique);\n        renderIPBreakdown();\n      } else if(msg.kind===\'new_attacker\'){\n        toast(\'⚠ NEW ATTACKER: \'+msg.data.ip, true);\n        const ip=msg.data.ip;\n        if(!ipStats[ip]) ipStats[ip]={packets:0,trapped:0,techniques:new Set()};\n        renderIPBreakdown();\n      }\n    }catch(_){}\n  };\n  es.onerror=()=>{setTimeout(connectSSE,3000);es.close()};\n}\n\nwindow.addEventListener(\'DOMContentLoaded\', async()=>{\n  connectSSE();\n  // First poll loads all historical data from server memory\n  await poll();\n  setInterval(poll, 4000);\n});\n</script>\n</body></html>'}

def page(key):
    r = make_response(HTML_PAGES[key])
    r.headers["Content-Type"] = "text/html; charset=utf-8"
    return r

@app.route("/")           
def route_overview():    return page("overview")
@app.route("/traffic")    
def route_traffic():     return page("traffic")
@app.route("/honeypots")  
def route_honeypots():   return page("honeypots")
@app.route("/attackers")  
def route_attackers():   return page("attackers")

@app.route("/api/state")
def api_state(): return jsonify(orchestrator.get_state())

@app.route("/api/stream")
def api_stream():
    def generate():
        last = time.time()
        yield 'data: {"kind":"connected"}\n\n'
        while True:
            for ev in orchestrator.drain_events(last):
                last = ev["ts"]
                yield f"data: {json.dumps({'kind': ev['kind'], 'data': ev['data']})}\n\n"
            yield 'data: {"kind":"heartbeat"}\n\n'
            time.sleep(1)
    return Response(generate(), mimetype="text/event-stream",
        headers={"Cache-Control":"no-cache","X-Accel-Buffering":"no","Connection":"keep-alive"})

@app.route("/api/ingest", methods=["POST"])
def api_ingest():
    b = request.get_json(silent=True) or {}
    return jsonify(orchestrator.ingest_attack(
        src_ip=b.get("src_ip","0.0.0.0"), dst_port=int(b.get("dst_port",80)),
        technique=b.get("technique","port_scan"), protocol=b.get("protocol","TCP"),
        payload_size=int(b.get("payload_size",200)), entropy=float(b.get("entropy",0.1)),
        packets_per_sec=float(b.get("packets_per_sec",5)), unique_ports=int(b.get("unique_ports",1)),
        syn_ratio=float(b.get("syn_ratio",0.1)), failed_auths=float(b.get("failed_auths",0)),
    ))

@app.route("/api/attacker/register", methods=["POST"])
def api_register():
    b = request.get_json(silent=True) or {}
    orchestrator.register_attacker(ip=b.get("ip","unknown"), profile=b.get("profile","Unknown"), skill=int(b.get("skill",1)))
    return jsonify({"ok": True})

@app.route("/api/attacker/deregister", methods=["POST"])
def api_deregister():
    b = request.get_json(silent=True) or {}
    orchestrator.deregister_attacker(b.get("ip",""))
    return jsonify({"ok": True})

